// The merchant name a feed row's logo resolves from — the backend's canonical
// `mkey` (e.g. "chatgpt") first, else the raw bank name. CategoryIcon turns it
// into a bundled logo, a favicon, or the category tile. Never matched loosely:
// see logo_service.
String _logoOf(Map row) => (row['mkey'] ?? row['nm'] ?? '').toString();
String _eur(num v, {bool signed = false}) => Money.format(v.toDouble(), signed: signed);

// Whole-euro format (no cents) for headline balances, e.g. "7 049 €".
String _eur0(num v) {
  final digits = v.abs().round().toString();
  final b = StringBuffer();
  for (var i = 0; i < digits.length; i++) {
    if (i != 0 && (digits.length - i) % 3 == 0) b.write(' ');
    b.write(digits[i]);
  }
  return '${v < 0 ? '−' : ''}$b €';
}

// ── Canonical money rule — the ONE definition every screen uses so the same
// concept shows the same number everywhere (mirrors functions/dashboard.py
// _flow/_totals). Direction decides income vs expense; transfers/exchange are
// excluded from both; a refund nets spending down. NEVER raw-sum amounts for a
// displayed "net" — that double-counts transfers between the user's own accounts.
String _flowOf(Map t) {
  if (t['sec'] == 'Pervedimai') return 'transfer';
  if (t['cat'] == 'Grąžinimas') return 'refund';
  return (t['a'] as num) > 0 ? 'income' : 'expense';
}

// A transaction's contribution to "spent": an outflow counts, a refund nets down.
double _spendOf(Map t) {
  final f = _flowOf(t);
  return (f == 'expense' || f == 'refund') ? -(t['a'] as num).toDouble() : 0.0;
}

double _sumExpenses(Iterable rows) =>
    rows.fold(0.0, (s, t) => s + _spendOf(t as Map));

double _sumIncome(Iterable rows) => rows.fold(0.0,
    (s, t) => s + (_flowOf(t as Map) == 'income' ? (t['a'] as num).toDouble() : 0.0));

// "Gauta" — money that actually LANDED in the account from outside: genuine
// income plus incoming transfers (P2P from people, top-ups). This is a
// DISPLAY-ONLY figure layered on top of the canonical rule; it must NEVER feed
// net / savings / budgets (those stay on _sumIncome). Refunds are excluded —
// they already net down "Išleista", so counting them here would double-represent
// the same money. Only positive legs count, so an outgoing transfer never
// reduces it. ⚠️ Single-bank-safe only: once multi-bank lands, own-account
// inbound transfers (SEB→Revolut) must be neutralised first (see M5) or this
// over-counts the user's own money moving between accounts.
double _receivedOf(Map t) {
  // Own-account transfers (SEB → Revolut etc., tagged "Savas pervedimas" by the
  // multi-bank backend) are the user's own money moving — never "received".
  if (t['cat'] == 'Savas pervedimas') return 0.0;
  final f = _flowOf(t);
  final a = (t['a'] as num).toDouble();
  return (a > 0 && (f == 'income' || f == 'transfer')) ? a : 0.0;
}

double _sumReceived(Iterable rows) =>
    rows.fold(0.0, (s, t) => s + _receivedOf(t as Map));

