// ── Recurring lifecycle (client side) ───────────────────────────────────────
// The backend now tags each recurring stream with a lifecycle status and a
// monthly-normalized amount, and only ACTIVE bills feed the projection (a
// finished tax plan / paid-off loan drops out). These helpers read that shape
// and layer the user's manual overrides on top (Monarch/Copilot-style).

// User-given names for anonymous recurring series (e.g. an "APPLE.COM/BILL"
// stream the user labelled "ChatGPT"), keyed by the series id (sid). Cached so
// rendering doesn't re-read Hive per row; reloaded after an edit.
Map<String, String>? _subAliasCache;
Map<String, String> _subAliases() =>
    _subAliasCache ??= DashboardStore.subscriptionAliases();
void _reloadSubAliases() => _subAliasCache = DashboardStore.subscriptionAliases();

/// Display name for a recurring item — the user's alias if the series is named,
/// otherwise the (shortened) merchant name.
String _recName(Map it) {
  final sid = it['sid'] as String?;
  if (sid != null) {
    final a = _subAliases()[sid];
    if (a != null && a.isNotEmpty) return a;
  }
  return _shortNm((it['name'] as String?) ?? '—');
}

/// Display name for a transaction feed row — the subscription alias if this row
/// belongs to a named recurring series (by sid), otherwise the merchant name.
String _txDisplayName(Map r) {
  final sid = r['sid'] as String?;
  if (sid != null) {
    final a = _subAliases()[sid];
    if (a != null && a.isNotEmpty) return a;
  }
  return (r['nm'] as String?) ?? '—';
}

/// The backend `subs.items` as typed maps
/// ({name, monthly, cost, cycle, status, active, type, occ, lastCharge}).
/// Tolerant of the legacy baked-preview shape (a `[name, cost]` pair) so the
/// standalone design preview keeps rendering.
List<Map<String, dynamic>> _recItems(Map subs) {
  final raw = (subs['items'] as List?) ?? const [];
  return raw.map<Map<String, dynamic>>((e) {
    if (e is Map) return e.cast<String, dynamic>();
    if (e is List && e.length >= 2) {
      return {
        'name': e[0], 'monthly': e[1], 'cost': e[1], 'cycle': 'monthly',
        'status': 'active', 'active': true, 'type': 'subscription', 'occ': 0,
      };
    }
    return {'name': '—', 'monthly': 0, 'active': false, 'type': 'subscription'};
  }).toList();
}

/// Whether a stream counts toward the monthly commitment: the backend says it's
/// an ACTIVE bill (not a transfer), unless the user overrode that verdict.
bool _recCounted(Map it, Set<String> excl, Set<String> incl) {
  final name = (it['name'] as String? ?? '').toLowerCase();
  if (excl.contains(name)) return false;
  if (incl.contains(name)) return true;
  return it['active'] == true && it['type'] != 'transfer';
}

double _recMonthlyTotal(List<Map<String, dynamic>> items, Set<String> excl, Set<String> incl) =>
    items.fold(0.0, (s, it) =>
        s + (_recCounted(it, excl, incl) ? ((it['monthly'] ?? 0) as num).toDouble() : 0.0));

List<String> _recStatusMeta(String? status) {
  // label + whether it reads as "live"
  switch (status) {
    case 'active': return ['Aktyvus', '1'];
    case 'late': return ['Vėluoja', '0'];
    case 'ended': return ['Baigėsi', '0'];
    case 'early': return ['Naujas', '0'];
    default: return ['', '0'];
  }
}

String _recCycleLabel(String? cycle) {
  switch (cycle) {
    case 'weekly': return 'kas savaitę';
    case 'quarterly': return 'kas ketvirtį';
    case 'yearly': return 'kas metus';
    default: return 'kas mėnesį';
  }
}

const _recMonLt = ['', 'sausio', 'vasario', 'kovo', 'balandžio', 'gegužės', 'birželio',
  'liepos', 'rugpjūčio', 'rugsėjo', 'spalio', 'lapkričio', 'gruodžio'];

// "kas mėnesį · paskutinį kartą liepos 14 · ×6" — helps the user judge each row.
String _recDetail(Map it) {
  final parts = <String>[_recCycleLabel(it['cycle'] as String?)];
  final last = it['lastCharge'] as String?;
  final d = last != null ? DateTime.tryParse(last) : null;
  if (d != null) parts.add('paskutinį kartą ${_recMonLt[d.month]} ${d.day}');
  final occ = ((it['occ'] ?? 0) as num).toInt();
  if (occ >= 2) parts.add('×$occ');
  return parts.join(' · ');
}

// Lowercase + strip Lithuanian diacritics so search matches "ivairus" ↔ "įvairūs".
String _fold(String s) {
  const m = {'ą': 'a', 'č': 'c', 'ę': 'e', 'ė': 'e', 'į': 'i', 'š': 's', 'ų': 'u', 'ū': 'u', 'ž': 'z'};
  final b = StringBuffer();
  for (final ch in s.toLowerCase().split('')) {
    b.write(m[ch] ?? ch);
  }
  return b.toString();
}

String _shortNm(String n) {
  // collapse an exactly-doubled name ("VMI prie LR FM VMI prie LR FM" → "VMI prie LR FM")
  final w = n.trim().split(RegExp(r'\s+'));
  if (w.length >= 2 && w.length.isEven && w.sublist(0, w.length ~/ 2).join(' ') == w.sublist(w.length ~/ 2).join(' ')) {
    n = w.sublist(0, w.length ~/ 2).join(' ');
  }
  n = n.replaceAll(RegExp(r'\s+Lt,?\s+X?-?\d+$', caseSensitive: false), ''); // "Maxima Lt X587" / "Maxima Lt, X-603" → "Maxima"
  n = n.replaceAll(RegExp(r'\s+X-?\d{2,}$'), '');
  n = n.replaceAll(RegExp(r' (MB|UAB|AB)$', caseSensitive: false), '');
  n = n.replaceAll(RegExp(r'^Www\.', caseSensitive: false), '');
  n = n.replaceAll(RegExp(r'\.lt$', caseSensitive: false), '');
  final i = n.indexOf('(');
  if (i > 0) n = n.substring(0, i);
  return n.trim();
}

List<String> _ptype(Map t) {
  final badges = ((t['badges'] as List?) ?? const []).cast<String>();
  if (badges.contains('rec')) {
    return ['Sąskaita', 'pasikartoja kas mėnesį · matoma ir „Prenumeratose"'];
  }
  if (t['col'] == 'transfer') return ['Pervedimas', 'neįskaičiuojama į išlaidas'];
  if (t['col'] == 'income' || t['pos'] == true) return ['Pajamos', ''];
  if (((t['count'] ?? 0) as num) > 1) {
    return ['Dažnas pirkimas', '${t['count']}× tą pačią dieną'];
  }
  return ['Vienkartinis', ''];
}

// Account avatar built from the backend `icon` field (main.py: 'R' for Revolut,
// 'bank' otherwise, 'cash' for cash) — NEVER a hardcoded bank. 'cash' → wallet
// glyph, 'R' or a revolut-named account → the Revolut letter, otherwise the
// first letter of the account name (SEB → "S"). The connected bank varies per
// user, so every account row must read this, not assume Revolut.
Widget _acctGlyph(Map a, {double diameter = 40, double fontSize = 18}) {
  final icon = ((a['icon'] as String?) ?? '').trim();
  final name = ((a['name'] as String?) ?? '').trim();
  final isCash = icon == 'cash';
  Widget child;
  if (isCash) {
    child = Icon(Icons.payments_outlined, size: diameter * 0.5, color: _purple);
  } else if (icon == 'R' || name.toLowerCase().contains('revolut')) {
    child = Text('R', style: TextStyle(fontSize: fontSize, fontWeight: FontWeight.w800, color: _ink));
  } else {
    final letter = name.isNotEmpty ? name.substring(0, 1).toUpperCase() : '•';
    child = Text(letter, style: TextStyle(fontSize: fontSize, fontWeight: FontWeight.w800, color: _ink));
  }
  // The bank's own logo when we ship it (SEB, Revolut, Swedbank…), keyed off the
  // backend's `bank` label — never a hardcoded bank, since which one is
  // connected varies per user. Bundled asset first (on-device), favicon next,
  // the letter above as the final fallback.
  final bankName = (a['bank'] as String?) ?? name;
  final asset = isCash ? null : logoAssetForName(bankName);
  final domain = (isCash || asset != null) ? null : domainForName(bankName);
  final pad = EdgeInsets.all(diameter * 0.18);
  if (asset != null) {
    child = Padding(
      padding: pad,
      child: Image.asset(asset, fit: BoxFit.contain,
          errorBuilder: (_, __, ___) => Center(child: child)),
    );
  } else if (domain != null) {
    final fallback = child;
    child = Padding(
      padding: pad,
      child: CachedNetworkImage(
        imageUrl: logoUrlForDomain(domain),
        fit: BoxFit.contain,
        placeholder: (_, __) => Center(child: fallback),
        errorWidget: (_, __, ___) => Center(child: fallback),
      ),
    );
  }
  return Container(
    width: diameter, height: diameter, alignment: Alignment.center,
    decoration: BoxDecoration(
      shape: BoxShape.circle,
      color: isCash ? _purpleSoft : _card,
      border: Border.all(color: _hair, width: 1.5),
    ),
    clipBehavior: Clip.antiAlias,
    child: child,
  );
}

class DashboardPreview extends StatefulWidget {
  /// [data] is the live dashboard payload from a bank connection. When null the
  /// screen falls back to the baked sample data (standalone design preview).
  /// [deeper] is an optional in-flight fuller (12-month) scan: the screen opens
  /// instantly on the fast (3-month) [data] and quietly swaps in the deeper
  /// result when it arrives (recent-first loading).
  const DashboardPreview({super.key, this.data, this.deeper});
  final Map<String, dynamic>? data;
  final Future<Map<String, dynamic>?>? deeper;
  @override
  State<DashboardPreview> createState() => _DashboardPreviewState();
}

class _DashboardPreviewState extends State<DashboardPreview> with WidgetsBindingObserver {
  late Map<String, dynamic> _d =
      widget.data ?? jsonDecode(utf8.decode(base64Decode(_dashB64))) as Map<String, dynamic>;
  bool _deepening = false; // a fuller 12-month scan is still loading in the background
  int _tab = 0;
  bool _hideBal = false;
  int? _weekSel; // tapped weekday bar
  int _shownPast = 2; // how many past months are shown below the current one
  final _txFilter = _TxFilter(); // feed filter (type + sections)

  // The transactions the feed shows — all, or filtered when the filter is active.
  Iterable<Map<String, dynamic>> get _feedAll {
    final all = (_d['all'] as List).cast<Map<String, dynamic>>();
    return _txFilter.active ? all.where(_txFilter.matches) : all;
  }

  Future<void> _openDashFilter() async {
    final avail = (_d['all'] as List).cast<Map<String, dynamic>>().map((t) => t['sec'] as String).toSet().toList()..sort();
    final res = await _showFilterSheet(context, _txFilter, avail);
    if (res == null) return;
    setState(() {
      _txFilter
        ..type = res.type
        ..secs = res.secs;
    });
  }

  // Cached non-dashboard tabs. They depend only on the immutable `_d` data, so
  // rebuilding them on every tab switch (setState) is wasted work that made tab
  // taps lag — build once and reuse; only a theme flip invalidates them.
  List<Widget>? _otherTabs;
  List<Widget> _buildOtherTabs() => [
        _OverviewTab(
          all: (_d['all'] as List).cast<Map<String, dynamic>>(),
          balance: _d['balance'] as Map<String, dynamic>,
          budgets: (_d['budgets'] as Map).cast<String, dynamic>(),
        ),
        _placeholder('AI Chat'),
        _PlanningTab(
          all: (_d['all'] as List).cast<Map<String, dynamic>>(),
          subs: _d['subs'] as Map<String, dynamic>,
        ),
        _AccountTab(balance: _d['balance'] as Map<String, dynamic>),
      ];

  // Theme flip must rebuild the cached tabs so their colours update.
  void _onTheme() => setState(() => _otherTabs = null);
  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addObserver(this); // auto-sync on resume
    _themeVN.addListener(_onTheme); // rebuild the whole tree when theme flips
    // Let any detail/edit screen that mutates `_d['all']` (delete, edit,
    // convert, recategorise) ask the dashboard to recompute + persist.
    _dashRefresh = _refreshFromAll;
    // Recent-first: the fast 3-month scan is already showing; when the deeper
    // scan lands, swap it in (fuller history + complete recurring), persist it,
    // and refresh reminders. Failures leave the fast scan in place.
    final deeper = widget.deeper;
    if (deeper != null) {
      _deepening = true;
      deeper.then((full) {
        if (!mounted) return;
        // The deeper scan re-fetches EVERY connected bank, so it can come back
        // missing one (a bank that rate-limited us during the connect burst).
        // It gets the same guard as a manual refresh: never trade complete data
        // for a fuller-but-holed one.
        if (_refreshLostABank(full)) {
          setState(() => _deepening = false);
          return;
        }
        setState(() {
          if (full != null) {
            _d = full;
            _otherTabs = null; // Overview/Planning rebuild from the fuller data
          }
          _deepening = false;
        });
        if (full != null) {
          _persist();
          _rescheduleReminders(full);
        }
      }).catchError((_) {
        if (mounted) setState(() => _deepening = false);
      });
    } else {
      // Opened from the persisted dashboard (not a fresh connect) → auto-sync in
      // the background if the data is stale.
      WidgetsBinding.instance.addPostFrameCallback((_) => _maybeAutoSync());
    }
  }

  @override
  void didChangeAppLifecycleState(AppLifecycleState state) {
    if (state == AppLifecycleState.resumed) _maybeAutoSync();
  }

  // Background auto-sync (Bilance-style ~30-min freshness): when the dashboard is
  // shown or the app returns to the foreground and the last sync is stale,
  // silently re-fetch all connected banks (6-month window + AI) and swap the
  // fresher data in. No-op in the standalone preview (no connected banks).
  static const _autoSyncEvery = Duration(minutes: 30);
  // Bank names currently represented in a dashboard payload's accounts.
  Set<String> _banksIn(Map<String, dynamic>? d) {
    final accts = ((d?['balance'] as Map?)?['accounts'] as List?) ?? const [];
    return accts
        .map((a) => ((a as Map)['bank'] as String?)?.toLowerCase().trim())
        .whereType<String>()
        .where((b) => b.isNotEmpty)
        .toSet();
  }

  // Per-account diagnostics from the last refresh — says WHY a bank dropped out.
  List<dynamic> _lastDiag = const [];

  // True when the last scan failed to fetch [bank] because the bank was rate-
  // limiting us. That's a "try again in a bit", not a broken connection.
  bool _wasRateLimited(Set<String> banks) => _lastDiag.any((e) =>
      e is Map &&
      e['rateLimited'] == true &&
      banks.contains((e['bank'] as String?)?.toLowerCase().trim()));

  // A refresh must NEVER make a bank silently vanish. If the fresh result lost a
  // bank the current view shows, keep the last-known data and tell the user
  // instead of overwriting with a bank-less result.
  bool _refreshLostABank(Map<String, dynamic>? fresh) {
    if (fresh == null) return false;
    final lost = _banksIn(_d).difference(_banksIn(fresh));
    if (lost.isEmpty) return false;
    final names = lost.map((b) => b.toUpperCase()).join(', ');
    // Reconnecting a rate-limited bank spends more of the quota that ran out —
    // exactly the wrong advice. Nor is it minutes: Enable Banking's guidance for
    // a bank that has cut us off is to come back in ~6 hours, so promising a
    // quick retry would just send the user back to pull again, and again.
    final msg = _wasRateLimited(lost)
        ? '$names kol kas neatiduoda naujų duomenų. Rodomi paskutiniai — '
            'atsinaujins savaime, kai bankas vėl leis.'
        : 'Nepavyko atnaujinti: $names. Rodomi paskutiniai duomenys — '
            'perjunk banką, jei kartojasi.';
    ScaffoldMessenger.of(context)
      ..hideCurrentSnackBar()
      ..showSnackBar(SnackBar(content: Text(msg), duration: const Duration(seconds: 5)));
    return true;
  }

  // Manual pull-to-refresh. A full multi-month, multi-account bank scan is
  // network-bound (~20-30s), so DON'T hold the pull spinner that long — it reads
  // as frozen. Release it quickly and let the scan run in the background, where
  // its progress shows in the 'Sinchronizuojama' card until fresh data lands.
  // Banks rate-limit per hour, and one pull = a full multi-account scan. Pulling
  // again while the last scan is barely cold spends that quota for data that
  // cannot have changed — and a rate-limited bank comes back with no payments at
  // all. Say when the data is already fresh instead of burning the budget.
  static const _minBetweenManualSyncs = Duration(minutes: 2);

  Future<void> _forceSync() async {
    if (DashboardStore.bankCount == 0 || _deepening) return;
    final last = DashboardStore.syncedAt;
    if (last != null && DateTime.now().difference(last) < _minBetweenManualSyncs) {
      ScaffoldMessenger.of(context)
        ..hideCurrentSnackBar()
        ..showSnackBar(const SnackBar(
          content: Text('Duomenys ką tik atnaujinti.'),
          duration: Duration(seconds: 2),
        ));
      return;
    }
    unawaited(_runSync());
    // A brief, honest beat so the pull gesture feels acknowledged before the
    // spinner closes and the 'Sinchronizuojama' card takes over.
    await Future<void>.delayed(const Duration(milliseconds: 650));
  }

  Future<void> _runSync() async {
    try {
      final refs = DashboardStore.accountRefs();
      if (refs.isEmpty) return;
      if (!mounted) return;
      setState(() => _deepening = true);
      final fresh = await BankingService.instance.refreshDashboard(refs,
          aiEnrichment: true, monthsBack: 6, onDiag: (d) => _lastDiag = d);
      if (!mounted) return;
      if (_refreshLostABank(fresh)) {
        setState(() => _deepening = false);
        return; // keep the complete last-known data; don't save the partial
      }
      setState(() {
        if (fresh != null) {
          _d = fresh;
          _otherTabs = null;
        }
        _deepening = false;
      });
      if (fresh != null) {
        await DashboardStore.save(fresh);
        _rescheduleReminders(fresh);
      }
    } catch (_) {
      if (mounted) setState(() => _deepening = false);
    }
  }

  Future<void> _maybeAutoSync() async {
    try {
      if (_deepening || DashboardStore.bankCount == 0) return;
      final last = DashboardStore.syncedAt;
      if (last != null && DateTime.now().difference(last) < _autoSyncEvery) return;
      final refs = DashboardStore.accountRefs();
      if (refs.isEmpty) return;
      if (!mounted) return;
      setState(() => _deepening = true);
      final fresh = await BankingService.instance.refreshDashboard(refs,
          aiEnrichment: true, monthsBack: 6, onDiag: (d) => _lastDiag = d);
      if (!mounted) return;
      if (_refreshLostABank(fresh)) {
        setState(() => _deepening = false);
        return; // keep the complete last-known data; don't save the partial
      }
      setState(() {
        if (fresh != null) {
          _d = fresh;
          _otherTabs = null;
        }
        _deepening = false;
      });
      if (fresh != null) {
        await DashboardStore.save(fresh); // updates syncedAt → resets the timer
        _rescheduleReminders(fresh);
      }
    } catch (_) {
      if (mounted) setState(() => _deepening = false);
    }
  }

  Future<void> _rescheduleReminders(Map<String, dynamic> dash) async {
    try {
      final subs = (dash['subs'] as Map?)?.cast<String, dynamic>();
      final items = ((subs?['items'] as List?) ?? const [])
          .whereType<Map>()
          .map((e) => e.cast<String, dynamic>())
          .toList();
      final isLt = Localizations.localeOf(context).languageCode == 'lt';
      await NotificationService.instance.scheduleFromRecurring(
        items,
        excluded: DashboardStore.recurringExcluded(),
        included: DashboardStore.recurringIncluded(),
        isLithuanian: isLt,
      );
    } catch (_) {/* reminders are best-effort */}
  }

  @override
  void dispose() {
    WidgetsBinding.instance.removeObserver(this);
    _themeVN.removeListener(_onTheme);
    if (_dashRefresh == _refreshFromAll) _dashRefresh = null;
    super.dispose();
  }

  // Re-derive everything from `_d['all']` after an external mutation and persist.
  void _refreshFromAll() {
    if (!mounted) return;
    setState(() {
      _d.remove('totals'); // month/day headers recompute canonically from `all`
      _d['week'] = _computeWeek((_d['all'] as List).cast<Map<String, dynamic>>());
      _otherTabs = null; // Overview/Planning rebuild
    });
    _persist();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
