  // ── DASHBOARD ──────────────────────────────────────────────────────────────
  Widget _dashboard() {
    final all = _feedAll;
    final keys = <String>{};
    for (final t in all) {
      keys.add((t['d'] as String).substring(0, 7));
    }
    final monthKeys = keys.toList()..sort((a, b) => b.compareTo(a));
    final shown = monthKeys.take(1 + _shownPast).toList(); // current + N past months

    return RefreshIndicator(
      onRefresh: _forceSync,
      color: _purple,
      backgroundColor: _card,
      child: ListView(
      physics: const AlwaysScrollableScrollPhysics(),
      padding: const EdgeInsets.only(bottom: 28),
      children: [
        _header(),
        _filters(),
        _balanceCard(),
        _syncedCard(),
        _subsCard(),
        _weekSection(),
        _aiPrompt(),
        // Bilance-style interleaved feed: transactions top→bottom; at each past-month
        // boundary a purple review card, then that month's transactions continue.
        for (var i = 0; i < shown.length; i++) ...[
          _monthHeaderFor(shown[i]),
          if (i > 0) _reviewCardFor(shown[i]),
          for (final dd in _monthFeed(shown[i])) _dayGroup(dd),
        ],
        if (monthKeys.length > shown.length)
          Padding(
            padding: const EdgeInsets.fromLTRB(16, 14, 16, 4),
            child: GestureDetector(
              onTap: () => setState(() => _shownPast += 2),
              child: Container(
                padding: const EdgeInsets.symmetric(vertical: 14),
                alignment: Alignment.center,
                decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(14), border: Border.all(color: _hair)),
                child: Text('Rodyti senesnius (${monthKeys.length - shown.length})',
                    style: const TextStyle(fontSize: 15, fontWeight: FontWeight.w700, color: _purple)),
              ),
            ),
          ),
        const SizedBox(height: 16),
      ],
    ));
  }

  int _monthCount(String mk) => _feedAll.where((t) => (t['d'] as String).startsWith(mk)).length;

  // ── Canonical month figures — the SINGLE source of truth so the same concept
  // shows the same number everywhere. Prefer the backend `totals` block; fall
  // back to the shared top-level _flowOf/_spendOf rule.
  Map<String, dynamic>? get _totalsBlock => _d['totals'] as Map<String, dynamic>?;

  Map<String, dynamic>? _monthTotals(String mk) =>
      (_totalsBlock?['months'] as Map?)?[mk] as Map<String, dynamic>?;

  Iterable<Map<String, dynamic>> _rowsForMonth(String mk) =>
      _feedAll.where((t) => (t['d'] as String).startsWith(mk));

  double _monthExpenses(String mk) {
    // Backend totals cover the whole month; when a filter is active they don't
    // match the shown rows, so compute from the filtered rows instead.
    if (!_txFilter.active) {
      final m = _monthTotals(mk);
      if (m != null) return (m['expenses'] as num).toDouble();
    }
    return _sumExpenses(_rowsForMonth(mk));
  }

  double _monthIncome(String mk) {
    if (!_txFilter.active) {
      final m = _monthTotals(mk);
      if (m != null) return (m['income'] as num).toDouble();
    }
    return _sumIncome(_rowsForMonth(mk));
  }

  // Canonical month net = income − expenses (NOT a raw sum of amounts, which
  // double-counts transfers between the user's own accounts).
  double _monthNet(String mk) => _monthIncome(mk) - _monthExpenses(mk);

  Widget _monthHeaderFor(String mk) => _monthHeader(
      _monNom[int.parse(mk.substring(5, 7)) - 1],
      _monthExpenses(mk), _monthIncome(mk));

  static const _wdFull = ['Pirmadienis', 'Antradienis', 'Trečiadienis', 'Ketvirtadienis', 'Penktadienis', 'Šeštadienis', 'Sekmadienis'];

  // Build a day-by-day feed for a month from the flat `all` list (merging same
  // merchant on the same day into an N× row, like the current-month feed).
  List<Map<String, dynamic>> _monthFeed(String mk) {
    final rows = _feedAll.where((t) => (t['d'] as String).startsWith(mk)).toList();
    final byDate = <String, List<Map<String, dynamic>>>{};
    for (final t in rows) {
      byDate.putIfAbsent(t['d'] as String, () => []).add(t);
    }
    final days = byDate.keys.toList()..sort((a, b) => b.compareTo(a));
    final out = <Map<String, dynamic>>[];
    for (final d in days) {
      final dayTx = byDate[d]!;
      final merged = <String, Map<String, dynamic>>{};
      for (final t in dayTx) {
        final k = t['mkey'] as String;
        final m = merged.putIfAbsent(k, () => {
              'nm': t['nm'], 'cat': t['cat'], 'ic': t['ic'], 'col': t['col'],
              'a': 0.0, 'count': 0, 'badges': t['badges'], 'amb': t['amb'], 'pos': t['pos'],
              // identity + fields so the detail screen can find/edit/delete the
              // underlying row(s): a group shares (mkey, date).
              'mkey': k, 'd': d, 'sec': t['sec'], 'secc': t['secc'], 'star': t['star'] == true,
            });
        if (t['star'] == true) m['star'] = true;
        m['a'] = (m['a'] as double) + (t['a'] as num).toDouble();
        m['count'] = (m['count'] as int) + 1;
      }
      final tx = merged.values.map((m) => {...m, 'count': (m['count'] as int) > 1 ? m['count'] : 0}).toList();
      // Day "spent" uses the canonical rule (expenses only) so it stays
      // consistent with the month header and category totals.
      final total = dayTx.fold(0.0, (s, t) => s + _spendOf(t));
      final dt = DateTime.parse(d);
      out.add({'date': d, 'wd': _wdFull[dt.weekday - 1], 'day': dt.day, 'total': total, 'tx': tx});
    }
    return out;
  }

