  Widget _weekSection() {
    // When a filter is active, recompute the week chart from the filtered rows
    // so it stays consistent with the filtered feed and headers.
    final week = _txFilter.active
        ? _computeWeek(_feedAll.toList())
        : _d['week'] as Map<String, dynamic>;
    final days = (week['days'] as List).cast<Map<String, dynamic>>();
    final total = (week['total'] as num).toDouble();
    double maxV = 1;
    for (final d in days) {
      final t = (d['total'] as num).toDouble();
      if (t > maxV) maxV = t;
    }
    return Column(
      children: [
        Padding(
          padding: const EdgeInsets.fromLTRB(20, 6, 20, 8),
          child: Row(children: [
            Text('Šios savaitės išlaidos', style: TextStyle(fontSize: 14.5, color: _muted, fontWeight: FontWeight.w500)),
            const Spacer(),
            // Positive amount — consistent with the month header's "Išleista X".
            Text(_eur(total), style: TextStyle(fontSize: 15, fontWeight: FontWeight.w700, color: _ink)),
          ]),
        ),
        Container(
          margin: const EdgeInsets.fromLTRB(16, 0, 16, 16),
          padding: const EdgeInsets.fromLTRB(10, 16, 10, 10),
          decoration: BoxDecoration(
            color: _bg,
            borderRadius: BorderRadius.circular(16),
            border: Border.all(color: _hair),
          ),
          child: LayoutBuilder(
            builder: (context, c) {
              final w = c.maxWidth;
              final sel = _weekSel;
              return Stack(
                clipBehavior: Clip.none,
                children: [
                  SizedBox(
                    height: 168,
                    child: Row(
                      crossAxisAlignment: CrossAxisAlignment.end,
                      children: [
                        for (var i = 0; i < days.length; i++) _bar(days[i], maxV, i),
                      ],
                    ),
                  ),
                  if (sel != null)
                    Positioned(
                      left: ((sel + 0.5) / days.length * w - 110).clamp(0.0, (w - 220).clamp(0.0, double.infinity)),
                      top: -102,
                      child: _weekTip(days[sel]),
                    ),
                ],
              );
            },
          ),
        ),
      ],
    );
  }

  Widget _bar(Map<String, dynamic> d, double maxV, int i) {
    final cats = (d['cats'] as List).cast<Map<String, dynamic>>();
    final tot = (d['total'] as num).toDouble();
    final h = tot > 0 ? (tot / maxV * 118).clamp(3.0, 118.0) : 2.0;
    final selected = _weekSel == i;
    return Expanded(
      child: GestureDetector(
        behavior: HitTestBehavior.opaque,
        onTap: () => setState(() => _weekSel = selected ? null : i),
        child: Column(
          mainAxisAlignment: MainAxisAlignment.end,
          children: [
            Text(tot > 0 ? '${tot.round()}€' : '',
                style: TextStyle(fontSize: 11.5, fontWeight: FontWeight.w700, color: selected ? _purple : _muted)),
            const SizedBox(height: 8),
            Opacity(
              opacity: (_weekSel == null || selected) ? 1 : 0.4,
              child: ClipRRect(
                borderRadius: BorderRadius.circular(9),
                child: SizedBox(
                  width: 15,
                  height: h,
                  child: tot > 0
                      ? Column(
                          verticalDirection: VerticalDirection.up,
                          children: [
                            for (final ct in cats)
