const _monNom = ['Sausis', 'Vasaris', 'Kovas', 'Balandis', 'Gegužė', 'Birželis', 'Liepa', 'Rugpjūtis', 'Rugsėjis', 'Spalis', 'Lapkritis', 'Gruodis'];
const _monGen = ['Sausio', 'Vasario', 'Kovo', 'Balandžio', 'Gegužės', 'Birželio', 'Liepos', 'Rugpjūčio', 'Rugsėjo', 'Spalio', 'Lapkričio', 'Gruodžio'];
String _dateLabel(DateTime t) => '${_monAbbr[t.month - 1]} ${t.day}';
String _kEur(double v) => v.abs() >= 1000 ? '${(v / 1000).toStringAsFixed(1)}K€' : '${v.toStringAsFixed(0)}€';
String _eurRound(double v) {
  final s = Money.format(v.roundToDouble());
  final c = s.indexOf(',');
  return c > 0 ? '${s.substring(0, c)} €' : s;
}

/// Total-balance detail sheet: reconstructed balance-over-time area chart with a
/// 1M/3M/YTD/1Y/Max range selector, plus the synced-accounts breakdown.
///
/// LOGIC: balance history is not stored by the bank — it's reconstructed by
/// walking backwards from the current balance over available transactions. Long
/// ranges therefore clamp to the earliest data we have (a freshly-connected
/// account only has ~90d under PSD2, so 1Y/Max == 3M until history accrues).
class _BalanceSheet extends StatefulWidget {
  const _BalanceSheet({required this.bal});
  final Map<String, dynamic> bal;
  @override
  State<_BalanceSheet> createState() => _BalanceSheetState();
}

class _BalanceSheetState extends State<_BalanceSheet> {
  String _range = '3M';
  int? _scrubI; // finger-scrub index into the filtered series
  static const _ranges = ['1M', '3M', 'YTD', '1Y', 'Max'];

  late final List<Map<String, dynamic>> _all =
      (widget.bal['series'] as List).cast<Map<String, dynamic>>();
  late final DateTime _last = DateTime.parse(_all.last['d'] as String);
  late final DateTime _first = DateTime.parse(_all.first['d'] as String);

  DateTime _cutoffFor(String r) {
    switch (r) {
      case '1M':
        return _last.subtract(const Duration(days: 30));
      case '3M':
        return _last.subtract(const Duration(days: 90));
      case 'YTD':
        return DateTime(_last.year, 1, 1);
      case '1Y':
        return _last.subtract(const Duration(days: 365));
      default:
        return _first;
    }
  }

  bool get _clamped => _range != 'Max' && _cutoffFor(_range).isBefore(_first);

  List<Map<String, dynamic>> get _filtered {
    var cutoff = _cutoffFor(_range);
    if (cutoff.isBefore(_first)) cutoff = _first;
    return _all.where((p) => !DateTime.parse(p['d'] as String).isBefore(cutoff)).toList();
  }

  @override
  Widget build(BuildContext context) {
    final pts = _filtered;
    final vals = pts.map((p) => (p['v'] as num).toDouble()).toList();
    final mn = vals.reduce((a, b) => a < b ? a : b);
    final mx = vals.reduce((a, b) => a > b ? a : b);
    final startD = DateTime.parse(pts.first['d'] as String);
    final endD = DateTime.parse(pts.last['d'] as String);
    final accounts = ((widget.bal['accounts'] as List?) ?? const []).cast<Map<String, dynamic>>();

    return DraggableScrollableSheet(
      initialChildSize: 0.82,
      minChildSize: 0.5,
      maxChildSize: 0.94,
      expand: false,
      builder: (_, controller) => ListView(
        controller: controller,
        padding: const EdgeInsets.only(bottom: 30),
        children: [
          Padding(
            padding: const EdgeInsets.fromLTRB(20, 16, 20, 8),
            child: Row(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                GestureDetector(
                  onTap: () => Navigator.pop(context),
                  child: Padding(
                    padding: const EdgeInsets.only(right: 14, top: 2),
                    child: Icon(Icons.close_rounded, size: 24, color: _ink),
                  ),
                ),
                Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text('Bendras likutis', style: TextStyle(fontSize: 15, color: _muted, fontWeight: FontWeight.w500)),
                    const SizedBox(height: 2),
                    Text(_eur(((widget.bal['current'] ?? 0) as num).toDouble()),
                        style: TextStyle(fontSize: 27, fontWeight: FontWeight.w800, color: _ink, letterSpacing: -0.5)),
                  ],
                ),
              ],
            ),
          ),
          // chart with axis labels + finger scrub
          Padding(
            padding: const EdgeInsets.fromLTRB(20, 8, 20, 6),
            child: LayoutBuilder(
              builder: (context, c) {
                const yW = 46.0, xH = 26.0;
                const totalH = 210.0;
                final plotW = c.maxWidth - yW;
                const plotH = totalH - xH;
                final n = vals.length;
                final si = _scrubI?.clamp(0, n - 1);
                double sx = 0, sy = 0;
                if (si != null) {
                  final range = (mx - mn).abs() < 1e-6 ? 1.0 : (mx - mn);
                  sx = n <= 1 ? 0 : si / (n - 1) * plotW;
                  sy = plotH - (vals[si] - mn) / range * (plotH - 6) - 3;
                }
                return SizedBox(
                  height: totalH,
                  child: Stack(
                    clipBehavior: Clip.none,
                    children: [
                      Positioned(
                        left: 0,
                        top: 0,
                        right: yW,
                        bottom: xH,
                        child: GestureDetector(
                          behavior: HitTestBehavior.opaque,
                          onTapDown: (d) => _scrub(d.localPosition.dx, plotW, n),
                          onTapUp: (_) => setState(() => _scrubI = null),
                          onTapCancel: () => setState(() => _scrubI = null),
                          onHorizontalDragStart: (d) => _scrub(d.localPosition.dx, plotW, n),
                          onHorizontalDragUpdate: (d) => _scrub(d.localPosition.dx, plotW, n),
                          onHorizontalDragEnd: (_) => setState(() => _scrubI = null),
                          onHorizontalDragCancel: () => setState(() => _scrubI = null),
                          child: CustomPaint(painter: _AreaChartPainter(vals, mn, mx, si), size: Size.infinite),
                        ),
                      ),
                      Positioned(
                        right: 0,
                        top: 0,
                        bottom: xH,
                        width: yW,
                        child: Padding(
                          padding: const EdgeInsets.only(left: 6),
                          child: Column(
                            mainAxisAlignment: MainAxisAlignment.spaceBetween,
                            crossAxisAlignment: CrossAxisAlignment.start,
                            children: [
                              Text(_kEur(mx), style: TextStyle(fontSize: 12, color: _muted, fontWeight: FontWeight.w600)),
                              Text(_kEur((mx + mn) / 2), style: TextStyle(fontSize: 12, color: _muted, fontWeight: FontWeight.w600)),
                              Text(_kEur(mn), style: TextStyle(fontSize: 12, color: _muted, fontWeight: FontWeight.w600)),
                            ],
                          ),
                        ),
                      ),
                      Positioned(
                        left: 0,
                        right: yW,
                        bottom: 0,
                        child: Row(
                          mainAxisAlignment: MainAxisAlignment.spaceBetween,
                          children: [
                            Text(_dateLabel(startD), style: TextStyle(fontSize: 12.5, color: _muted)),
                            Text(_dateLabel(endD), style: TextStyle(fontSize: 12.5, color: _muted)),
                          ],
                        ),
                      ),
                      if (si != null)
                        Positioned(
                          left: (sx - 52).clamp(0.0, (plotW - 104).clamp(0.0, double.infinity)),
                          top: (sy - 58).clamp(-34.0, plotH - 40),
                          child: _tip(vals[si], DateTime.parse(pts[si]['d'] as String)),
                        ),
                    ],
                  ),
                );
              },
            ),
          ),
          // range selector
          Padding(
            padding: const EdgeInsets.fromLTRB(20, 10, 20, 8),
            child: Container(
              padding: const EdgeInsets.all(4),
              decoration: BoxDecoration(color: _soft, borderRadius: BorderRadius.circular(14)),
              child: Row(
                children: [
                  for (final r in _ranges)
                    Expanded(
                      child: GestureDetector(
                        behavior: HitTestBehavior.opaque,
                        onTap: () => setState(() => _range = r),
                        child: Container(
                          alignment: Alignment.center,
                          padding: const EdgeInsets.symmetric(vertical: 10),
                          decoration: BoxDecoration(
                            color: _range == r ? Colors.white : Colors.transparent,
                            borderRadius: BorderRadius.circular(11),
                            boxShadow: _range == r
                                ? [BoxShadow(color: Colors.black.withValues(alpha: 0.06), blurRadius: 6, offset: const Offset(0, 2))]
                                : null,
                          ),
                          child: Text(r,
                              style: TextStyle(
                                  fontSize: 14,
                                  fontWeight: FontWeight.w700,
                                  color: _range == r ? _purple : _muted)),
                        ),
                      ),
                    ),
                ],
              ),
            ),
          ),
          if (_clamped)
            Container(
              margin: const EdgeInsets.fromLTRB(20, 4, 20, 4),
              padding: const EdgeInsets.all(11),
              decoration: BoxDecoration(
                color: _soft,
                borderRadius: BorderRadius.circular(12),
              ),
              child: Row(
                children: [
                  const Icon(Icons.info_outline_rounded, size: 16, color: _purple),
                  const SizedBox(width: 8),
                  Expanded(
                    child: Text(
                      'Rodoma ${_monthsAvail()} mėn. — tiek istorijos grąžino bankas. Daugiau prisipildys laikui bėgant.',
                      style: TextStyle(fontSize: 12, color: _ink, height: 1.35),
                    ),
                  ),
                ],
              ),
            ),
          const Divider(height: 24, thickness: 1, color: Color(0xFFECECEF)),
          for (var i = 0; i < accounts.length; i++) ...[
            _accountRow(accounts[i]),
            if (i != accounts.length - 1) const RowDivider(indent: 68),
          ],
        ],
      ),
    );
  }

  int _monthsAvail() => ((_last.difference(_first).inDays) / 30).round();

  void _scrub(double dx, double plotW, int n) {
    if (n <= 1) {
      setState(() => _scrubI = 0);
      return;
    }
    var i = (dx / plotW * (n - 1)).round();
    if (i < 0) i = 0;
    if (i > n - 1) i = n - 1;
    setState(() => _scrubI = i);
  }

  Widget _tip(double v, DateTime d) {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 7),
      decoration: BoxDecoration(
        color: _card,
        borderRadius: BorderRadius.circular(12),
        border: Border.all(color: _hair),
        boxShadow: [BoxShadow(color: Colors.black.withValues(alpha: 0.10), blurRadius: 12, offset: const Offset(0, 4))],
      ),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          Text(_eurRound(v), style: TextStyle(fontSize: 16, fontWeight: FontWeight.w800, color: _ink)),
          Text(_dateLabel(d), style: TextStyle(fontSize: 13, color: _muted)),
        ],
      ),
    );
  }

  Widget _accountRow(Map<String, dynamic> a) {
    return Padding(
      padding: const EdgeInsets.symmetric(horizontal: 20, vertical: 14),
      child: Row(
        children: [
          _acctGlyph(a),
          const SizedBox(width: 12),
          Expanded(
            child: Text(a['name'] as String, style: TextStyle(fontSize: 16, fontWeight: FontWeight.w700, color: _ink)),
          ),
          Column(
            crossAxisAlignment: CrossAxisAlignment.end,
            children: [
              Text(a['sub'] != null ? '${a['sub']}' : _eur(((a['amount'] ?? 0) as num).toDouble()),
                  style: TextStyle(fontSize: 16, fontWeight: FontWeight.w700, color: _ink)),
              if (a['sub'] != null)
                Text(_eur(((a['amount'] ?? 0) as num).toDouble()), style: TextStyle(fontSize: 12.5, color: _muted)),
            ],
          ),
        ],
      ),
    );
  }
}

class _AreaChartPainter extends CustomPainter {
  _AreaChartPainter(this.vals, this.mn, this.mx, [this.scrubIndex]);
  final List<double> vals;
  final double mn, mx;
  final int? scrubIndex;

  @override
  void paint(Canvas canvas, Size size) {
    if (vals.length < 2) return;
    final range = (mx - mn).abs() < 1e-6 ? 1.0 : (mx - mn);
    Offset at(int i) {
      final x = i / (vals.length - 1) * size.width;
      final y = size.height - (vals[i] - mn) / range * (size.height - 6) - 3;
      return Offset(x, y);
    }

    // dashed gridlines (3)
    final grid = Paint()
      ..color = const Color(0xFFE6E6EC)
      ..strokeWidth = 1;
    for (final f in [0.0, 0.5, 1.0]) {
      final y = 3 + f * (size.height - 6);
      double x = 0;
      while (x < size.width) {
        canvas.drawLine(Offset(x, y), Offset(x + 4, y), grid);
        x += 9;
      }
    }

    final line = Path()..moveTo(at(0).dx, at(0).dy);
    for (var i = 1; i < vals.length; i++) {
      line.lineTo(at(i).dx, at(i).dy);
    }

    final area = Path.from(line)
      ..lineTo(size.width, size.height)
      ..lineTo(0, size.height)
      ..close();
    canvas.drawPath(
      area,
      Paint()
        ..shader = const LinearGradient(
          begin: Alignment.topCenter,
          end: Alignment.bottomCenter,
          colors: [Color(0x336D28D9), Color(0x066D28D9)],
        ).createShader(Offset.zero & size),
    );
    canvas.drawPath(
      line,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 2.4
        ..strokeCap = StrokeCap.round
        ..strokeJoin = StrokeJoin.round
        ..color = _purple,
    );

    // finger-scrub crosshair + dot
    if (scrubIndex != null && scrubIndex! >= 0 && scrubIndex! < vals.length) {
      final p = at(scrubIndex!);
      canvas.drawLine(
        Offset(p.dx, 0),
        Offset(p.dx, size.height),
        Paint()
          ..color = _purple.withValues(alpha: 0.40)
          ..strokeWidth = 1.5,
      );
      canvas.drawCircle(p, 6.5, Paint()..color = Colors.white);
      canvas.drawCircle(
        p,
        6.5,
        Paint()
          ..style = PaintingStyle.stroke
          ..strokeWidth = 2.5
          ..color = _purple,
      );
      canvas.drawCircle(p, 3, Paint()..color = _purple);
    }
  }

  @override
  bool shouldRepaint(_AreaChartPainter old) =>
      old.vals != vals || old.mn != mn || old.mx != mx || old.scrubIndex != scrubIndex;
}

