                          const SizedBox(height: 2),
                          Row(children: [
                            Flexible(child: Text(widget.tx['manual'] == true ? 'Įvesta ranka' : 'Kategorizuota automatiškai', maxLines: 1, overflow: TextOverflow.ellipsis, style: TextStyle(fontSize: 12.5, color: _muted))),
