  Widget _budgetCard(double limit) {
    final spent = _catSpentThisMonth();
    final left = limit - spent;
    final ratio = (spent / limit).clamp(0.0, 1.0);
    final over = left < 0;
    return Padding(
      padding: const EdgeInsets.fromLTRB(20, 0, 20, 16),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Text('$_txMonthGen biudžetas', style: TextStyle(fontSize: 12.5, color: _muted, fontWeight: FontWeight.w600)),
          const SizedBox(height: 8),
          AppCard(color: _card, border: _hair, 
            padding: const EdgeInsets.all(15),
            child: Column(
              children: [
                Row(children: [
                  CategoryIcon(icon: _catIcon, color: _catColor, size: 36),
                  const SizedBox(width: 10),
                  Expanded(child: Text(_cat, style: TextStyle(fontSize: 15.5, fontWeight: FontWeight.w700, color: _ink))),
                  Text(_eur(limit).replaceAll(',00', ''), style: TextStyle(fontSize: 16, fontWeight: FontWeight.w800, color: _ink)),
                ]),
                const SizedBox(height: 12),
                Row(children: [
                  Text('${_eur(spent)} išleista', style: TextStyle(fontSize: 12.5, color: _muted)),
                  const Spacer(),
                  Text(over ? '${_eur(-left)} viršyta' : '${_eur(left)} liko',
                      style: TextStyle(fontSize: 12.5, fontWeight: FontWeight.w700, color: over ? DS.danger : _good)),
                ]),
                const SizedBox(height: 8),
                ClipRRect(
                  borderRadius: BorderRadius.circular(5),
                  child: LinearProgressIndicator(
                    value: ratio,
                    minHeight: 8,
                    backgroundColor: const Color(0xFFE7F0E8),
                    valueColor: AlwaysStoppedAnimation(over ? DS.danger : _good),
                  ),
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }

  Widget _accountCard() {
    // Only name an account when the scan has exactly one — otherwise we can't
    // tell which account this transaction belongs to (rows carry no account id),
    // so showing any single bank would be a guess. Hide it instead of lying.
    if (widget.accounts.length != 1) return const SizedBox.shrink();
    final a = widget.accounts.first;
    final label = (a['name'] as String?)?.trim();
    if (label == null || label.isEmpty) return const SizedBox.shrink();
    return Padding(
      padding: const EdgeInsets.fromLTRB(20, 0, 20, 16),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Text('Sąskaita', style: TextStyle(fontSize: 12.5, color: _muted, fontWeight: FontWeight.w600)),
          const SizedBox(height: 8),
          AppCard(color: _card, border: _hair,
            padding: const EdgeInsets.all(14),
            child: Row(children: [
              _acctGlyph(a, diameter: 38, fontSize: 17),
              const SizedBox(width: 12),
              Text(label, style: TextStyle(fontSize: 15.5, fontWeight: FontWeight.w700, color: _ink)),
            ]),
          ),
        ],
      ),
    );
  }

  Widget _similarSection(List<Map<String, dynamic>> items) {
    final show = items.take(15).toList();
    return Padding(
      padding: const EdgeInsets.fromLTRB(20, 4, 20, 0),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(children: [
            Text('Panašūs sandoriai', style: TextStyle(fontSize: 20, fontWeight: FontWeight.w800, color: _ink, letterSpacing: -0.3)),
            const SizedBox(width: 8),
            Text('${items.length}', style: TextStyle(fontSize: 14, fontWeight: FontWeight.w700, color: _muted)),
          ]),
          const SizedBox(height: 10),
          for (final s in show)
            Container(
              margin: const EdgeInsets.only(bottom: 8),
              padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 11),
              decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(16), border: Border.all(color: _hair)),
              child: Row(children: [
                CategoryIcon(icon: _iconOf(s['ic'] as String?), color: _colOf(s['col'] as String?), size: 40, circle: false, merchant: _logoOf(s)),
                const SizedBox(width: 12),
                Expanded(
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Text(_shortNm(s['nm'] as String), style: TextStyle(fontSize: 15.5, fontWeight: FontWeight.w700, color: _ink)),
                      const SizedBox(height: 2),
                      Row(children: [
                        Container(width: 5, height: 5, decoration: const BoxDecoration(shape: BoxShape.circle, color: _purple)),
                        const SizedBox(width: 6),
                        Flexible(child: Text('${s['md']}; ${s['cat']}', maxLines: 1, overflow: TextOverflow.ellipsis, style: TextStyle(fontSize: 12.5, color: _muted))),
                      ]),
                    ],
                  ),
                ),
                const SizedBox(width: 8),
                Text(_eur((s['a'] as num).toDouble(), signed: true),
                    style: TextStyle(fontSize: 15.5, fontWeight: FontWeight.w700, color: s['pos'] == true ? _good : _ink, fontFeatures: const [FontFeature.tabularFigures()])),
              ]),
            ),
          if (items.length > show.length)
            Padding(
              padding: const EdgeInsets.only(top: 4),
              child: Text('… ir dar ${items.length - show.length}', style: TextStyle(fontSize: 13, color: _muted)),
            ),
        ],
      ),
    );
  }
}

