// MONTH IN REVIEW — full screen (opened from the dashboard review card)
// ══════════════════════════════════════════════════════════════════════════════
class _SecAgg {
  _SecAgg(this.label, this.colorKey);
  final String label;
  final String colorKey;
  double net = 0;
  Color get color => _secColor[colorKey] ?? _muted;
  IconData get icon => _secIcon[_secToIcon[label]] ?? Icons.circle;
}

class _MonthReviewScreen extends StatefulWidget {
  const _MonthReviewScreen({required this.all, required this.balance, required this.budgets, required this.month, required this.monthNom, required this.monthGen, required this.onGoToBudgets});
  final List<Map<String, dynamic>> all;
  final Map<String, dynamic> balance;
  final Map<String, dynamic> budgets;
  final String month, monthNom, monthGen;
  final VoidCallback onGoToBudgets;
  @override
  State<_MonthReviewScreen> createState() => _MonthReviewScreenState();
}

class _MonthReviewScreenState extends State<_MonthReviewScreen> {
  List<Map<String, dynamic>> get _rows => widget.all.where((t) => (t['d'] as String).startsWith(widget.month)).toList();

  String get _prevMonth {
    final y = int.parse(widget.month.substring(0, 4));
    final m = int.parse(widget.month.substring(5, 7));
    return m == 1 ? '${y - 1}-12' : '$y-${(m - 1).toString().padLeft(2, '0')}';
  }

  String get _prevMonthNom => _monNom[(int.parse(widget.month.substring(5, 7)) + 10) % 12];

  bool _isIncome(String l) => l == 'Pajamos';
  bool _isTransfer(String l) => l == 'Pervedimai'; // 'Kita' = uncategorised spending, counts as expense

  List<_SecAgg> _sections() {
    final m = <String, _SecAgg>{};
    for (final t in _rows) {
      final label = t['sec'] as String;
      final a = m.putIfAbsent(label, () => _SecAgg(label, t['secc'] as String));
      a.net += (t['a'] as num).toDouble();
    }
    final list = m.values.toList()..sort((x, y) => y.net.abs().compareTo(x.net.abs()));
    return list;
  }

  @override
  Widget build(BuildContext context) {
    final secs = _sections();
    final expenseSecs = secs.where((s) => !_isIncome(s.label) && !_isTransfer(s.label) && s.net < 0).toList();
    // Headline figures use the canonical rule (transfers excluded, refunds net
    // spending down) so grynasis == earned − spent and matches the dashboard +
    // review card exactly — never the raw sum-of-amounts that inflated it before.
    final spent = _sumExpenses(_rows);
    final earned = _sumIncome(_rows);
    // "Gauta" = all money that landed from outside (income + incoming transfers).
    // Display-only — net/savings below still use `earned` (canonical income).
    final received = _sumReceived(_rows);
    final net = earned - spent;
    final savings = earned > 0 ? ((earned - spent) / earned * 100).round().clamp(0, 100) : 0;
    // Real saving streak (was hardcoded "2 mėn."), derived from all months.
    final mkeys = (widget.all.map((t) => (t['d'] as String).substring(0, 7)).toSet().toList()..sort());
    int savOf(List<Map<String, dynamic>> r) {
      final e = _sumIncome(r);
      return e > 0 ? ((e - _sumExpenses(r)) / e * 100).round().clamp(0, 100) : 0;
    }
    final streak = _streakOf(mkeys, (mk) => widget.all.where((t) => (t['d'] as String).startsWith(mk)).toList(), savOf);

    return Scaffold(
      backgroundColor: _bg,
      body: Column(
        children: [
          _header(),
          Expanded(
            child: ListView(
              padding: const EdgeInsets.only(bottom: 30),
              children: [
                const SizedBox(height: 14),
                _filters(),
                _donuts(spent, earned, received, expenseSecs),
                _totalCard(net),
                _statsRow(spent, earned, savings, net),
                _currencyNote(),
                _aiReport(spent, earned, expenseSecs, net),
                _balanceChart(),
                _calendar(),
                _savingsClub(savings, earned, streak),
                _categoryList(secs),
                _budgets(),
                _insights(),
                _avgDaily(expenseSecs),
                _merchants(),
                _largest(),
              ],
            ),
          ),
        ],
      ),
    );
  }

