  // ── helpers ──
  Map<String, double> _sectionSpend(String month) {
    final m = <String, double>{};
    for (final t in widget.all) {
      if (!(t['d'] as String).startsWith(month)) continue;
      final label = t['sec'] as String;
      if (_isIncome(label) || _isTransfer(label)) continue;
      final a = (t['a'] as num).toDouble();
      if (a < 0) m[label] = (m[label] ?? 0) - a;
    }
    return m;
  }

  Color _labelColor(String label) {
    final t = widget.all.firstWhere((t) => t['sec'] == label, orElse: () => const {});
    return _secColor[t['secc']] ?? _muted;
  }

  IconData _labelIcon(String label) => _secIcon[_secToIcon[label]] ?? Icons.circle;

  int get _daysInMonth {
    final y = int.parse(widget.month.substring(0, 4));
    final mo = int.parse(widget.month.substring(5, 7));
    return DateTime(y, mo + 1, 0).day;
  }

  Widget _sectionLabel(String s) => Padding(
        padding: const EdgeInsets.fromLTRB(20, 22, 20, 8),
        child: Text(s, style: TextStyle(fontSize: 22, fontWeight: FontWeight.w800, color: _ink, letterSpacing: -0.4)),
      );

  // ── CALENDAR heatmap ──
  Widget _calendar() {
    final y = int.parse(widget.month.substring(0, 4));
    final mo = int.parse(widget.month.substring(5, 7));
    final lead = DateTime(y, mo, 1).weekday - 1; // Mon=0
    final net = <int, double>{};
    final daySec = <int, Map<String, double>>{};
    for (final t in _rows) {
      final d = int.parse((t['d'] as String).substring(8, 10));
      final a = (t['a'] as num).toDouble();
      net[d] = (net[d] ?? 0) + a;
      final label = t['sec'] as String;
      if (!_isIncome(label) && !_isTransfer(label) && a < 0) {
        final sm = daySec.putIfAbsent(d, () => {});
        sm[t['secc'] as String] = (sm[t['secc'] as String] ?? 0) - a;
      }
    }
    Color? dom(int d) {
      final sm = daySec[d];
      if (sm == null || sm.isEmpty) return null;
      return _secColor[sm.entries.reduce((a, b) => a.value >= b.value ? a : b).key];
    }
    const wd = ['Pr', 'An', 'Tr', 'Kt', 'Pn', 'Št', 'Sk'];
    final cells = <Widget>[];
    for (var i = 0; i < lead; i++) {
      cells.add(const SizedBox());
    }
    for (var d = 1; d <= _daysInMonth; d++) {
      final n = net[d];
      final c = (n != null && n > 500) ? _secColor['amber'] : dom(d);
      cells.add(_calCell(d, n, c));
    }
    return Container(
      margin: const EdgeInsets.fromLTRB(16, 0, 16, 14),
      padding: const EdgeInsets.all(10),
      decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(16), border: Border.all(color: _hair)),
      child: Column(
        children: [
          Row(children: [for (final w in wd) Expanded(child: Center(child: Text(w, style: TextStyle(fontSize: 12, color: _muted, fontWeight: FontWeight.w600))))]),
          const SizedBox(height: 6),
          GridView.count(
            crossAxisCount: 7,
            shrinkWrap: true,
            physics: const NeverScrollableScrollPhysics(),
            childAspectRatio: 0.82,
            children: cells,
          ),
        ],
      ),
    );
  }

  Widget _calCell(int d, double? n, Color? c) {
    return Container(
      margin: const EdgeInsets.all(2),
      decoration: BoxDecoration(
        color: c?.withValues(alpha: 0.10) ?? Colors.transparent,
        borderRadius: BorderRadius.circular(8),
        border: Border.all(color: c?.withValues(alpha: 0.55) ?? _hair, width: 1.1),
      ),
      child: Column(
        mainAxisAlignment: MainAxisAlignment.center,
        children: [
          Text('$d', style: TextStyle(fontSize: 12, fontWeight: FontWeight.w700, color: _ink)),
          if (n != null) Text('${n.round()}€', style: TextStyle(fontSize: 9.5, fontWeight: FontWeight.w600, color: n >= 0 ? _good : _muted)),
        ],
      ),
    );
  }

  // ── BUDGETS ──
  Widget _budgets() {
    final b = widget.budgets;
    final spentByCat = <String, double>{};
    for (final t in _rows) {
      final a = (t['a'] as num).toDouble();
      if (a < 0) spentByCat[t['cat'] as String] = (spentByCat[t['cat'] as String] ?? 0) - a;
    }
    final cats = b.keys.toList();
    // No user budgets → don't show a budget section at all (it was showing fake
    // hardcoded example limits that confused people — "where did 880 € come from?").
    if (cats.isEmpty) return const SizedBox.shrink();
    final totalBudget = cats.fold(0.0, (s, c) => s + (b[c] as num).toDouble());
    final totalSpent = cats.fold(0.0, (s, c) => s + (spentByCat[c] ?? 0));
    final under = totalBudget - totalSpent;
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        _sectionLabel('Biudžetai'),
        Container(
          margin: const EdgeInsets.fromLTRB(16, 0, 16, 12),
          padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 14),
          decoration: BoxDecoration(
            borderRadius: BorderRadius.circular(16),
            gradient: const LinearGradient(begin: Alignment.topLeft, end: Alignment.bottomRight, colors: [_purpleDeep, _purple]),
          ),
          child: Text(
            // Honest scope: these are example limits covering only a few
            // categories, so never claim overall savings — state what was spent
            // in the tracked categories out of their (placeholder) limit.
            under >= 0
                ? 'Sekamose kategorijose išleidai ${totalSpent.round()} € iš ${totalBudget.round()} €.'
                : 'Viršijai sekamų kategorijų limitą ${(-under).round()} €.',
            style: const TextStyle(fontSize: 17, fontWeight: FontWeight.w800, color: Colors.white, height: 1.3),
          ),
        ),
        Padding(
          padding: const EdgeInsets.fromLTRB(16, 0, 16, 6),
          child: AppCard(color: _card, border: _hair, 
            padding: const EdgeInsets.all(15),
            child: Column(children: [
              Row(children: [
                Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                  Text('${totalSpent.round()} €', style: TextStyle(fontSize: 21, fontWeight: FontWeight.w800, color: _ink)),
                  Text('išleista', style: TextStyle(fontSize: 12.5, color: _muted)),
                ]),
                const Spacer(),
                SizedBox(
                  width: 56, height: 56,
                  child: Stack(alignment: Alignment.center, children: [
                    CustomPaint(size: const Size(56, 56), painter: _RingProgressPainter((totalSpent / totalBudget).clamp(0.0, 1.0))),
                    Text('${(totalSpent / totalBudget * 100).round()}%', style: TextStyle(fontSize: 13, fontWeight: FontWeight.w800, color: _ink)),
                  ]),
                ),
                const Spacer(),
                Column(crossAxisAlignment: CrossAxisAlignment.end, children: [
                  Text('${totalBudget.round()} €', style: TextStyle(fontSize: 21, fontWeight: FontWeight.w800, color: _ink)),
                  Text('biudžetas*', style: TextStyle(fontSize: 12.5, color: _muted)),
                ]),
              ]),
              const SizedBox(height: 6),
              Align(alignment: Alignment.centerRight, child: Text('* pavyzdiniai limitai', style: TextStyle(fontSize: 10.5, color: _faint))),
            ]),
          ),
        ),
        for (final c in cats)
          Padding(
            padding: const EdgeInsets.fromLTRB(16, 8, 16, 0),
            child: AppCard(color: _card, border: _hair, 
              padding: const EdgeInsets.all(14),
              child: _budgetBar(c, spentByCat[c] ?? 0, (b[c] as num).toDouble()),
            ),
          ),
        const SizedBox(height: 4),
      ],
    );
  }

  Widget _budgetBar(String cat, double spent, double limit) {
    final left = limit - spent;
    final over = left < 0;
    return Column(children: [
      Row(children: [
