  // ── INSIGHTS (June vs May) ──
  Widget _insights() {
    final cur = _sectionSpend(widget.month);
    final prev = _sectionSpend(_prevMonth);
    final labels = cur.keys.toList()..sort((a, b) => cur[b]!.compareTo(cur[a]!));
    final top = labels.take(3).toList();
    if (top.isEmpty) return const SizedBox.shrink();
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        _sectionLabel('Įžvalgos'),
        for (final l in top) _insightCard(l, prev[l] ?? 0, cur[l] ?? 0),
