  // ── MERCHANTS ──
  Widget _merchants() {
    final count = _rows
        .where((t) => !_isIncome(t['sec'] as String) && !_isTransfer(t['sec'] as String) && (t['a'] as num) < 0)
        .map((t) => t['mkey'])
