// OVERVIEW TAB — analytics for the selected period (defaults to current month)
// ══════════════════════════════════════════════════════════════════════════════
class _OverviewTab extends StatefulWidget {
  const _OverviewTab({required this.all, required this.balance, required this.budgets});
  final List<Map<String, dynamic>> all;
  final Map<String, dynamic> balance;
  final Map<String, dynamic> budgets;
  @override
  State<_OverviewTab> createState() => _OverviewTabState();
}

class _OverviewTabState extends State<_OverviewTab> {
  bool _merchantsOpen = false;
  String? _selKey; // chosen month (null = latest / "Šis mėnuo")
  bool _hide = false; // eye toggle → mask the headline amounts
  final _filter = _TxFilter();

  Future<void> _openFilter() async {
    final avail = _rows.map((t) => t['sec'] as String).toSet().toList()..sort();
    final res = await _showFilterSheet(context, _filter, avail);
    if (res == null) return;
    setState(() {
      _filter
        ..type = res.type
        ..secs = res.secs;
    });
  }

  List<String> get _monthKeys {
    final s = widget.all.map((t) => (t['d'] as String).substring(0, 7)).toSet().toList()..sort();
    return s; // ascending
  }

  String get _curKey {
    final keys = _monthKeys;
    if (_selKey != null && keys.contains(_selKey)) return _selKey!;
    return keys.last;
  }

  String get _monthLabel {
    final keys = _monthKeys;
    if (_selKey == null || _selKey == keys.last) return 'Šis mėnuo';
    return _monNom[int.parse(_selKey!.substring(5, 7)) - 1];
  }

  void _pickMonth() {
    final keys = _monthKeys.reversed.toList(); // newest first
    showModalBottomSheet<void>(
      context: context,
      backgroundColor: _card,
      shape: const RoundedRectangleBorder(borderRadius: BorderRadius.vertical(top: Radius.circular(22))),
      builder: (ctx) => SafeArea(
        child: Column(mainAxisSize: MainAxisSize.min, children: [
          const SizedBox(height: 12),
          Container(width: 40, height: 4, decoration: BoxDecoration(color: _faint, borderRadius: BorderRadius.circular(2))),
          Padding(
            padding: const EdgeInsets.fromLTRB(20, 14, 20, 6),
            child: Align(alignment: Alignment.centerLeft, child: Text('Laikotarpis', style: TextStyle(fontSize: 18, fontWeight: FontWeight.w800, color: _ink))),
          ),
          Flexible(
            child: ListView(shrinkWrap: true, children: [
              for (final k in keys)
                InkWell(
                  onTap: () {
                    setState(() => _selKey = k);
                    Navigator.pop(ctx);
                  },
                  child: Padding(
                    padding: const EdgeInsets.symmetric(horizontal: 20, vertical: 14),
                    child: Row(children: [
                      Expanded(
                        child: Text(
                          k == _monthKeys.last
                              ? 'Šis mėnuo'
                              : '${_monNom[int.parse(k.substring(5, 7)) - 1]} ${k.substring(0, 4)}',
                          style: TextStyle(fontSize: 16, fontWeight: FontWeight.w600, color: _ink),
                        ),
                      ),
                      if (k == _curKey) const Icon(Icons.check_rounded, size: 22, color: _purple),
                    ]),
                  ),
                ),
            ]),
          ),
          const SizedBox(height: 10),
        ]),
      ),
    );
  }
  int get _curMon => int.parse(_curKey.substring(5, 7));
  List<Map<String, dynamic>> _rowsOf(String mk) => widget.all.where((t) => (t['d'] as String).startsWith(mk)).toList();
  List<Map<String, dynamic>> get _rows => _rowsOf(_curKey);

  bool _isIncome(String l) => l == 'Pajamos';
  bool _isTransfer(String l) => l == 'Pervedimai';

  List<_SecAgg> _sections(List<Map<String, dynamic>> rows) {
    final m = <String, _SecAgg>{};
    for (final t in rows) {
      final a = m.putIfAbsent(t['sec'] as String, () => _SecAgg(t['sec'] as String, t['secc'] as String));
      a.net += (t['a'] as num).toDouble();
    }
    return m.values.toList()..sort((x, y) => y.net.abs().compareTo(x.net.abs()));
  }

  // Canonical rule (shared with the dashboard + review) so every Overview figure
  // matches: transfers/exchange excluded, refunds net spending down, and net =
  // income − expenses (never the raw sum that double-counts transfers).
  double _spentOf(List<Map<String, dynamic>> rows) => _sumExpenses(rows);
  double _earnedOf(List<Map<String, dynamic>> rows) => _sumIncome(rows);
  double _netOf(List<Map<String, dynamic>> rows) => _sumIncome(rows) - _sumExpenses(rows);
  // savings rate = share of income you didn't spend. Uses classified income
  // (salary incl. currency-converted salary + refunds), NOT all inflows —
  // account top-ups / transfers between your own accounts are not income and
  // would otherwise distort the rate.
  int _savingsOf(List<Map<String, dynamic>> rows) {
    final earned = _earnedOf(rows);
    final spent = _spentOf(rows);
    return earned > 0 ? ((earned - spent) / earned * 100).round().clamp(0, 100) : 0;
  }

  // Consecutive COMPLETED months (excluding the current, possibly-partial one)
  // where you actually saved (rate > 0). Unfiltered — the streak reflects your
  // saving history, not the on-screen filter, and a fresh month with no income
  // yet shouldn't reset it.
  int get _savingStreak => _streakOf(_monthKeys, _rowsOf, _savingsOf);

  @override
  Widget build(BuildContext context) {
    final rows = _filter.apply(_rows);
    final secs = _sections(rows);
    final expenseSecs = secs.where((s) => !_isIncome(s.label) && !_isTransfer(s.label) && s.net < 0).toList();
    final spent = _spentOf(rows);
    final earned = _earnedOf(rows);
    // "Gauta" = all inflows (income + incoming transfers); display-only, does not
    // touch net/savings which stay on canonical income (`earned`).
    final received = _sumReceived(rows);
    final net = _netOf(rows);
    final savings = _savingsOf(rows);
    // No income that month → a savings rate is undefined, so show "—" not "0 %".
    final savStr = earned > 0 ? '$savings %' : '—';
    final prevKey = _monthKeys.length > 1 ? _monthKeys[_monthKeys.length - 2] : null;
    final prevRows = prevKey != null ? _filter.apply(_rowsOf(prevKey)) : <Map<String, dynamic>>[];
    final prevStr = _earnedOf(prevRows) > 0 ? '${_savingsOf(prevRows)} %' : '—';

    return SafeArea(
      bottom: false,
      child: ListView(
        padding: const EdgeInsets.only(bottom: 28),
        children: [
          _header(),
          _filters(),
          _donuts(spent, earned, received, expenseSecs),
          _totalCard(net),
          _savingsCard(savStr, prevStr, _savingStreak),
          _categoryList(secs),
          _tags(),
          _analyticsLabel(),
          _calendar(),
          _merchants(),
          _last6(),
          _avgDaily(expenseSecs),
        ],
      ),
    );
  }

  Widget _header() => Padding(
        padding: const EdgeInsets.fromLTRB(16, 6, 16, 12),
        child: Row(children: [
          Text('Apžvalga', style: TextStyle(fontSize: 30, fontWeight: FontWeight.w800, color: _ink, letterSpacing: -0.5)),
          const Spacer(),
          GestureDetector(
            onTap: () => setState(() => _hide = !_hide),
            child: Icon(_hide ? Icons.visibility_off_outlined : Icons.visibility_outlined, size: 25, color: _ink),
          ),
          const SizedBox(width: 14),
          GestureDetector(
            onTap: () => Navigator.of(context).push(MaterialPageRoute(
                builder: (_) => _SearchScreen(all: widget.all, budgets: widget.budgets))),
            child: Icon(Icons.search_rounded, size: 25, color: _ink),
          ),
        ]),
      );

  Widget _filters() => Padding(
        padding: const EdgeInsets.fromLTRB(16, 0, 16, 10),
        child: Row(children: [
          GestureDetector(onTap: _pickMonth, child: _Chip(icon: Icons.calendar_today_rounded, label: _monthLabel)),
          const SizedBox(width: 9),
          GestureDetector(
            onTap: _openFilter,
            child: _Chip(
              icon: Icons.tune_rounded,
              label: _filter.active ? 'Filtras · ${_filter.count}' : 'Filtras',
              active: _filter.active,
            ),
          ),
        ]),
      );

  Widget _donuts(double spent, double earned, double received, List<_SecAgg> exp) {
    final other = (received - earned).clamp(0.0, double.infinity);
    return Padding(
      padding: const EdgeInsets.fromLTRB(16, 8, 16, 4),
      child: Row(children: [
        Expanded(child: _donut(spent, [for (final s in exp) [-s.net, s.color]], '−', 'Išleista')),
        Expanded(
          child: GestureDetector(
            onTap: () => _showReceivedBreakdown(context, earned, other),
            child: _donut(
              received,
              [if (earned > 0) [earned, _secColor['amber']!], if (other > 0) [other, _secColor['indigo']!]],
              '+', 'Gauta'),
          ),
        ),
      ]),
    );
  }

