  Widget _tags() => Padding(
        padding: const EdgeInsets.fromLTRB(16, 16, 16, 4),
        child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          Padding(padding: const EdgeInsets.only(left: 4, bottom: 8), child: Text('Žymos', style: TextStyle(fontSize: 13.5, color: _muted))),
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 16),
            decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(14), border: Border.all(color: _hair)),
            child: Row(children: [const Icon(Icons.add_rounded, size: 22, color: _purple), const SizedBox(width: 12), Text('Pridėti žymą', style: TextStyle(fontSize: 15.5, fontWeight: FontWeight.w600, color: _ink))]),
          ),
        ]),
      );

  Widget _analyticsLabel() => Padding(
        padding: const EdgeInsets.fromLTRB(20, 24, 20, 10),
        child: Text('Analitika', style: TextStyle(fontSize: 26, fontWeight: FontWeight.w800, color: _ink, letterSpacing: -0.4)),
      );

  // ── calendar ──
  Widget _calendar() {
    final y = int.parse(_curKey.substring(0, 4));
    final lead = DateTime(y, _curMon, 1).weekday - 1;
    final daysIn = DateTime(y, _curMon + 1, 0).day;
    final net = <int, double>{};
    final daySec = <int, Map<String, double>>{};
    for (final t in _rows) {
      final d = int.parse((t['d'] as String).substring(8, 10));
      final a = (t['a'] as num).toDouble();
      net[d] = (net[d] ?? 0) + a;
      final label = t['sec'] as String;
      if (!_isIncome(label) && !_isTransfer(label) && a < 0) {
        (daySec.putIfAbsent(d, () => {}))[t['secc'] as String] = ((daySec[d]![t['secc'] as String]) ?? 0) - a;
      }
    }
    Color? dom(int d) {
      final sm = daySec[d];
      if (sm == null || sm.isEmpty) return null;
      return _secColor[sm.entries.reduce((a, b) => a.value >= b.value ? a : b).key];
    }
    const wd = ['Pr', 'An', 'Tr', 'Kt', 'Pn', 'Št', 'Sk'];
    final cells = <Widget>[];
    for (var i = 0; i < lead; i++) {
      cells.add(const SizedBox());
    }
    for (var d = 1; d <= daysIn; d++) {
      final n = net[d];
      final c = (n != null && n > 500) ? _secColor['amber'] : dom(d);
      cells.add(Container(
        margin: const EdgeInsets.all(2),
        decoration: BoxDecoration(
          color: c?.withValues(alpha: 0.10) ?? Colors.transparent,
          borderRadius: BorderRadius.circular(8),
          border: Border.all(color: c?.withValues(alpha: 0.55) ?? _hair, width: 1.1),
        ),
        child: Column(mainAxisAlignment: MainAxisAlignment.center, children: [
          Text('$d', style: TextStyle(fontSize: 12, fontWeight: FontWeight.w700, color: _ink)),
          if (n != null) Text('${n.round()}€', style: TextStyle(fontSize: 9.5, fontWeight: FontWeight.w600, color: n >= 0 ? _good : _muted)),
        ]),
      ));
    }
    return Container(
      margin: const EdgeInsets.fromLTRB(16, 0, 16, 14),
      padding: const EdgeInsets.all(10),
      decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(16), border: Border.all(color: _hair)),
      child: Column(children: [
        Row(children: [for (final w in wd) Expanded(child: Center(child: Text(w, style: TextStyle(fontSize: 12, color: _muted, fontWeight: FontWeight.w600))))]),
        const SizedBox(height: 6),
        GridView.count(crossAxisCount: 7, shrinkWrap: true, physics: const NeverScrollableScrollPhysics(), childAspectRatio: 0.82, children: cells),
      ]),
    );
  }

  // ── merchants ──
  Widget _merchants() {
    final m = <String, List<dynamic>>{}; // mkey -> [name, sum, count]
    for (final t in _rows) {
      // merchants = places you spent; skip income + internal transfers
      if (_isIncome(t['sec'] as String) || _isTransfer(t['sec'] as String) || (t['a'] as num) >= 0) continue;
      final k = t['mkey'] as String;
      final e = m.putIfAbsent(k, () => [t['nm'], 0.0, 0]);
      e[1] = (e[1] as double) + (t['a'] as num).toDouble();
      e[2] = (e[2] as int) + 1;
    }
    final list = m.values.toList()..sort((a, b) => (a[1] as double).abs().compareTo((b[1] as double).abs()) * -1);
    return Padding(
      padding: const EdgeInsets.fromLTRB(16, 0, 16, 14),
      child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
        Padding(padding: const EdgeInsets.only(left: 4, bottom: 8), child: Text('Prekybininkai', style: TextStyle(fontSize: 13.5, color: _muted))),
        Container(
          decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(14), border: Border.all(color: _hair)),
          child: Column(children: [
            InkWell(
              onTap: () => setState(() => _merchantsOpen = !_merchantsOpen),
              child: Padding(
                padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 16),
                child: Row(children: [
                  Text('${list.length} prekybininkai', style: TextStyle(fontSize: 16, fontWeight: FontWeight.w700, color: _ink)),
                  const Spacer(),
                  Icon(_merchantsOpen ? Icons.keyboard_arrow_up_rounded : Icons.keyboard_arrow_down_rounded, color: _purple),
                ]),
              ),
            ),
            if (_merchantsOpen)
              for (final e in list) ...[
                Divider(height: 1, thickness: 1, color: _hair),
                Padding(
                  padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 13),
                  child: Row(children: [
                    if ((e[2] as int) > 1) ...[
                      Container(
                        padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
                        decoration: BoxDecoration(color: _purple, borderRadius: BorderRadius.circular(6)),
                        child: Text('${e[2]}×', style: const TextStyle(fontSize: 11, fontWeight: FontWeight.w800, color: Colors.white)),
                      ),
                      const SizedBox(width: 10),
                    ],
                    Expanded(child: Text(_shortNm(e[0] as String), style: TextStyle(fontSize: 15.5, fontWeight: FontWeight.w600, color: _ink))),
                    Text(_eur(e[1] as double, signed: true), style: TextStyle(fontSize: 15.5, fontWeight: FontWeight.w700, color: _ink, fontFeatures: const [FontFeature.tabularFigures()])),
                  ]),
                ),
              ],
          ]),
        ),
      ]),
    );
  }

  // ── last 6 months (income up / spending down) ──
  Widget _last6() {
    final keys = _monthKeys.length > 6 ? _monthKeys.sublist(_monthKeys.length - 6) : _monthKeys;
    final inc = <double>[], spd = <double>[];
    for (final k in keys) {
      final r = _rowsOf(k);
      inc.add(_earnedOf(r));
      spd.add(_spentOf(r));
    }
    final total = keys.fold(0.0, (s, k) => s + _netOf(_rowsOf(k)));
    final maxUp = (inc.isEmpty ? 1.0 : inc.reduce((a, b) => a > b ? a : b)).clamp(1.0, double.infinity);
    final maxDn = (spd.isEmpty ? 1.0 : spd.reduce((a, b) => a > b ? a : b)).clamp(1.0, double.infinity);
    const upH = 150.0, dnH = 90.0;
    return Padding(
      padding: const EdgeInsets.fromLTRB(16, 0, 16, 14),
      child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
        Padding(
          padding: const EdgeInsets.fromLTRB(4, 0, 4, 10),
          child: Row(children: [
            Text('Paskutiniai 6 mėn.', style: TextStyle(fontSize: 14.5, color: _muted, fontWeight: FontWeight.w500)),
            const Spacer(),
            Text(_eur(total, signed: true), style: TextStyle(fontSize: 15, fontWeight: FontWeight.w700, color: total >= 0 ? _good : _ink)),
          ]),
        ),
        Container(
          padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 10),
          decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(16), border: Border.all(color: _hair)),
          child: Row(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              for (var i = 0; i < keys.length; i++)
                Expanded(
                  child: Column(children: [
                    Text(inc[i] >= 1 ? '+${_kEur(inc[i])}' : '', style: TextStyle(fontSize: 10, fontWeight: FontWeight.w700, color: _muted)),
                    SizedBox(
                      height: upH,
                      child: Align(
                        alignment: Alignment.bottomCenter,
                        child: Container(width: 16, height: (inc[i] / maxUp * upH).clamp(0.0, upH), decoration: BoxDecoration(color: _secColor['amber'], borderRadius: const BorderRadius.vertical(top: Radius.circular(8)))),
                      ),
                    ),
                    Container(height: 1, color: _hair),
                    SizedBox(
                      height: dnH,
                      child: Align(
                        alignment: Alignment.topCenter,
                        child: Container(width: 16, height: (spd[i] / maxDn * dnH).clamp(0.0, dnH), decoration: BoxDecoration(color: _secColor['green'], borderRadius: const BorderRadius.vertical(bottom: Radius.circular(8)))),
                      ),
                    ),
                    Text(spd[i] >= 1 ? '−${_kEur(spd[i])}' : '', style: TextStyle(fontSize: 10, fontWeight: FontWeight.w600, color: _muted)),
                    const SizedBox(height: 4),
                    Text(_monNom[int.parse(keys[i].substring(5, 7)) - 1].substring(0, 3), style: TextStyle(fontSize: 11.5, color: _muted, fontWeight: FontWeight.w500)),
                  ]),
                ),
            ],
          ),
        ),
      ]),
    );
  }

  // ── average daily spending (current month → per days ELAPSED, not full month) ──
  Widget _avgDaily(List<_SecAgg> exp) {
    final y = int.parse(_curKey.substring(0, 4));
    final daysInMonth = DateTime(y, _curMon + 1, 0).day;
    final latestDay = _rows.map((t) => int.parse((t['d'] as String).substring(8, 10))).fold(1, (a, b) => b > a ? b : a);
    final days = (latestDay + 1).clamp(1, daysInMonth);
    final totalAvg = exp.fold(0.0, (s, x) => s - x.net) / days;
    return Padding(
      padding: const EdgeInsets.fromLTRB(16, 0, 16, 20),
      child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
        Padding(padding: const EdgeInsets.only(left: 4, bottom: 8), child: Text('Vidutinės dienos išlaidos', style: TextStyle(fontSize: 13.5, color: _muted))),
        Container(
          padding: const EdgeInsets.all(16),
          decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(16), border: Border.all(color: _hair)),
          child: Column(children: [
            Row(children: [
              Text('Šį mėnesį', style: TextStyle(fontSize: 17, fontWeight: FontWeight.w800, color: _ink)),
              const Spacer(),
              Text('−${totalAvg.toStringAsFixed(2).replaceAll('.', ',')} €', style: TextStyle(fontSize: 17, fontWeight: FontWeight.w800, color: _ink)),
            ]),
            const SizedBox(height: 12),
            for (final s in exp)
              Padding(
                padding: const EdgeInsets.only(bottom: 9),
                child: Row(children: [
                  CategoryIcon(icon: s.icon, color: s.color, size: 26),
                  const SizedBox(width: 10),
                  Expanded(child: Text(s.label, style: TextStyle(fontSize: 14.5, color: _ink))),
                  Text('−${((-s.net) / days).toStringAsFixed(2).replaceAll('.', ',')} €', style: TextStyle(fontSize: 14.5, fontWeight: FontWeight.w700, color: _ink, fontFeatures: const [FontFeature.tabularFigures()])),
                ]),
              ),
          ]),
        ),
      ]),
    );
  }
}

// ══════════════════════════════════════════════════════════════════════════════
// SAVINGS RATE — detail screen
// ══════════════════════════════════════════════════════════════════════════════
class _SavingsRateScreen extends StatelessWidget {
  const _SavingsRateScreen({required this.monthKeys, required this.savingsOf, required this.earnedOf, required this.rowsOf});
  final List<String> monthKeys;
  final int Function(List<Map<String, dynamic>>) savingsOf;
  final double Function(List<Map<String, dynamic>>) earnedOf;
  final List<Map<String, dynamic>> Function(String) rowsOf;

  @override
  Widget build(BuildContext context) {
    final curKey = monthKeys.last;
    final curMon = int.parse(curKey.substring(5, 7));
    final rows = rowsOf(curKey);
    final earned = earnedOf(rows); // canonical income (matches Overview)
    final savings = savingsOf(rows);
    final savStr = earned > 0 ? '$savings %' : '—';
    final prevKey = monthKeys.length > 1 ? monthKeys[monthKeys.length - 2] : null;
    final prevMon = prevKey != null ? int.parse(prevKey.substring(5, 7)) : 0;
    final prevRows = prevKey != null ? rowsOf(prevKey) : <Map<String, dynamic>>[];
    final prevSavings = savingsOf(prevRows);
    final prevStr = earnedOf(prevRows) > 0 ? '$prevSavings %' : '—';
    final streak = _streakOf(monthKeys, rowsOf, savingsOf);
    final last6 = monthKeys.length > 6 ? monthKeys.sublist(monthKeys.length - 6) : monthKeys;

    return Scaffold(
      backgroundColor: _bg,
      body: SafeArea(
        bottom: false,
        child: Column(children: [
          Padding(
            padding: const EdgeInsets.fromLTRB(6, 4, 14, 8),
            child: Row(children: [
              IconButton(onPressed: () => Navigator.pop(context), icon: Icon(Icons.arrow_back_ios_new_rounded, size: 20, color: _ink)),
              Expanded(child: Text('Santaupų norma', style: TextStyle(fontSize: 20, fontWeight: FontWeight.w700, color: _ink))),
              Icon(Icons.help_outline_rounded, size: 24, color: _muted),
            ]),
          ),
          Expanded(
            child: ListView(
              padding: const EdgeInsets.fromLTRB(16, 8, 16, 30),
              children: [
                Container(
                  padding: const EdgeInsets.all(18),
                  decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(18), border: Border.all(color: _hair)),
                  child: Row(children: [
                    Expanded(
                      child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                        Text('${_monNom[curMon - 1]} pajamos', style: TextStyle(fontSize: 13, color: _muted)),
                        const SizedBox(height: 6),
                        Row(children: [
                          Container(width: 26, height: 26, alignment: Alignment.center, decoration: const BoxDecoration(color: _purple, shape: BoxShape.circle), child: const Icon(Icons.add_rounded, size: 16, color: Colors.white)),
                          const SizedBox(width: 8),
                          Text('${earned.round()} €', style: TextStyle(fontSize: 16, fontWeight: FontWeight.w800, color: _ink)),
                        ]),
                        const SizedBox(height: 16),
                        Text('${_monNom[curMon - 1]} santaupos', style: TextStyle(fontSize: 13, color: _muted)),
                        const SizedBox(height: 6),
                        Row(children: [
                          Container(width: 26, height: 26, alignment: Alignment.center, decoration: const BoxDecoration(color: _purple, shape: BoxShape.circle), child: const Icon(Icons.help_outline_rounded, size: 15, color: Colors.white)),
                          const SizedBox(width: 8),
                          Text(earned > 0 ? '${(earned * savings / 100).round()} €' : '—', style: TextStyle(fontSize: 16, fontWeight: FontWeight.w800, color: _ink)),
                        ]),
                      ]),
                    ),
                    Column(crossAxisAlignment: CrossAxisAlignment.end, children: [
                      Text('Santaupų norma', style: TextStyle(fontSize: 15, fontWeight: FontWeight.w600, color: _ink)),
                      Text(savStr, style: TextStyle(fontSize: 52, fontWeight: FontWeight.w800, color: _ink, height: 1.1)),
                      Text('santaupos / pajamos', style: TextStyle(fontSize: 11.5, color: _muted)),
                    ]),
                  ]),
                ),
                const SizedBox(height: 14),
                if (prevKey != null) ...[
                  Padding(padding: const EdgeInsets.only(left: 4, bottom: 6), child: Text('Praėjusio mėn. statusas', style: TextStyle(fontSize: 12.5, color: _muted))),
                  Container(
                    padding: const EdgeInsets.all(16),
                    decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(18), border: Border.all(color: _hair)),
                    child: Row(children: [
                      Expanded(
                        child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                          Text('${_monGen[prevMon - 1]} santaupų klubas', style: TextStyle(fontSize: 17, fontWeight: FontWeight.w800, color: _ink)),
                          const SizedBox(height: 10),
                          Container(
                            padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
                            decoration: BoxDecoration(color: _purpleSoft, borderRadius: BorderRadius.circular(20)),
                            child: Row(mainAxisSize: MainAxisSize.min, children: [
                              const Icon(Icons.military_tech_rounded, size: 15, color: _purple),
                              const SizedBox(width: 4),
                              Text(prevStr, style: const TextStyle(fontSize: 13, fontWeight: FontWeight.w800, color: _purple)),
                              if (streak >= 2) ...[
                                const SizedBox(width: 10),
                                const Icon(Icons.local_fire_department_rounded, size: 15, color: _purple),
                                const SizedBox(width: 2),
                                Text('$streak mėn.', style: const TextStyle(fontSize: 13, fontWeight: FontWeight.w600, color: _purple)),
                              ],
                            ]),
                          ),
                        ]),
                      ),
                      Container(
                        width: 76, height: 76, alignment: Alignment.center,
                        decoration: const BoxDecoration(color: _purple, shape: BoxShape.circle),
                        child: Column(mainAxisAlignment: MainAxisAlignment.center, children: [
                          Text(earnedOf(prevRows) > 0 ? '$prevSavings' : '—', style: const TextStyle(fontSize: 24, fontWeight: FontWeight.w800, color: Colors.white, height: 1)),
                          const Text('% klubas', style: TextStyle(fontSize: 9.5, fontWeight: FontWeight.w600, color: Colors.white)),
                        ]),
                      ),
                    ]),
                  ),
                ],
                const SizedBox(height: 16),
                Padding(padding: const EdgeInsets.only(left: 4, bottom: 8), child: Text('Paskutinių 6 mėn. normos', style: TextStyle(fontSize: 12.5, color: _muted))),
                Container(
                  padding: const EdgeInsets.fromLTRB(6, 16, 6, 8),
                  decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(16), border: Border.all(color: _hair)),
                  child: SizedBox(
                    height: 150,
                    child: Row(crossAxisAlignment: CrossAxisAlignment.end, children: [
                      for (final k in last6)
                        Expanded(
                          child: Column(mainAxisAlignment: MainAxisAlignment.end, children: [
                            Text('${savingsOf(rowsOf(k))} %', style: TextStyle(fontSize: 11.5, fontWeight: FontWeight.w700, color: _muted)),
                            const SizedBox(height: 6),
                            Container(width: 20, height: (savingsOf(rowsOf(k)) / 100 * 110).clamp(2.0, 110.0), decoration: BoxDecoration(color: _purple, borderRadius: BorderRadius.circular(6))),
                            const SizedBox(height: 8),
                            Text(_monNom[int.parse(k.substring(5, 7)) - 1].substring(0, 3), style: TextStyle(fontSize: 11.5, color: _muted)),
                          ]),
                        ),
                    ]),
                  ),
                ),
              ],
            ),
          ),
        ]),
      ),
    );
  }
}

// ══════════════════════════════════════════════════════════════════════════════
// PLANNING TAB — budgets (data-suggested limits) + recurring
// ══════════════════════════════════════════════════════════════════════════════
class _Budget {
  _Budget(this.sec, this.limit);
  final String sec;
  double limit;
  bool? auto; // true = we suggested the limit from history; false = user-set
  bool get isAuto => auto ?? true; // null (hot-reload) → treat as suggested
}

class _PlanningTab extends StatefulWidget {
  const _PlanningTab({required this.all, required this.subs});
  final List<Map<String, dynamic>> all;
  final Map<String, dynamic> subs;
  @override
  State<_PlanningTab> createState() => _PlanningTabState();
}

class _PlanningTabState extends State<_PlanningTab> {
  late List<_Budget> _budgets;
  bool _showBanner = true;
  String? _selKey; // selected month (null = latest / "Šis mėnuo")

  // ── month scope ────────────────────────────────────────────────────────────
  List<String> get _monthKeys {
    final s = widget.all.map((t) => (t['d'] as String).substring(0, 7)).toSet().toList()..sort();
    return s;
  }

  String get _curKey => _selKey ?? _monthKeys.last;
  int get _curMon => int.parse(_curKey.substring(5, 7));
  int get _curYear => int.parse(_curKey.substring(0, 4));
  List<Map<String, dynamic>> get _rows => widget.all.where((t) => (t['d'] as String).startsWith(_curKey)).toList();

  int get _daysInMonth => DateTime(_curYear, _curMon + 1, 0).day;
  int get _elapsedDays {
    final latest = _rows.map((t) => int.parse((t['d'] as String).substring(8, 10))).fold(1, (a, b) => b > a ? b : a);
    return (latest + 1).clamp(1, _daysInMonth);
  }

  // section label → colour key / icon (looked up from any tx in that section)
  final Map<String, String> _secColorKey = {};
  Color _colorOfSec(String sec) => _secColor[_secColorKey[sec]] ?? _muted;
  IconData _iconOfSec(String sec) => _secIcon[_secToIcon[sec]] ?? Icons.circle;


  // expenses only (positive €) in a section, over an arbitrary row set
  double _spentInSec(Iterable<Map<String, dynamic>> rows, String sec) => rows
      .where((t) => t['sec'] == sec && (t['a'] as num) < 0)
      .fold(0.0, (s, t) => s - (t['a'] as num).toDouble());

  // data-suggested monthly limit = a TYPICAL month + a little headroom.
  // Uses the median of complete months (robust to one-off spikes); if the section
  // only appears in the current partial month, extrapolates it to full-month pace.
  double _suggestLimit(String sec) {
    final months = _monthKeys;
    if (months.isEmpty) return 100;
    // complete months = everything except the current (partial) latest month
    final complete = months.length > 1 ? months.sublist(0, months.length - 1) : months;
    final vals = <double>[];
    for (final mk in complete) {
      final v = _spentInSec(widget.all.where((t) => (t['d'] as String).startsWith(mk)), sec);
      if (v > 0) vals.add(v);
    }
    double typical;
    if (vals.isEmpty) {
      final cur = _spentInSec(_rows, sec);
      typical = _elapsedDays > 0 ? cur / _elapsedDays * _daysInMonth : cur;
    } else {
      vals.sort();
      typical = vals[vals.length ~/ 2]; // median
    }
    final withHead = typical * 1.15; // ~15% headroom so a normal month fits
    if (withHead < 5) return 20;
    final step = withHead < 100 ? 10 : (withHead < 500 ? 25 : 50);
    return math.max(step.toDouble(), (withHead / step).ceil() * step.toDouble());
  }

  @override
  void initState() {
    super.initState();
    for (final t in widget.all) {
      _secColorKey.putIfAbsent(t['sec'] as String, () => t['secc'] as String);
    }
    // fallback colours for taxonomy sections the user has no transactions in yet
    for (final e in _taxonomy) {
      _secColorKey.putIfAbsent(e['sec'] as String, () => e['c'] as String);
    }
    // Start with NO budgets — auto-creating them confused users ("where did this
    // limit come from?"). The user adds their own; the add sheet still offers a
    // data-based suggested limit (median of real spend) to accept or edit.
    _budgets = [];
  }

  // pace-aware colour: red if already over, orange if trending over, else green
  Color _pace(double spent, double limit) {
    if (spent > limit) return const Color(0xFFE0574F);
    final projected = _elapsedDays > 0 ? spent / _elapsedDays * _daysInMonth : spent;
    if (projected > limit) return const Color(0xFFEE7A3A);
    return _good;
  }

  @override
  Widget build(BuildContext context) {
    final spentSoFar = _budgets.fold(0.0, (s, b) => s + _spentInSec(_rows, b.sec));
    final totalLimit = _budgets.fold(0.0, (s, b) => s + b.limit);

    return SafeArea(
      bottom: false,
      child: ListView(
        padding: const EdgeInsets.only(bottom: 28),
        children: [
          _header(),
          _monthFilter(),
          _sectionTitle('Biudžetai'),
          if (_showBanner) _banner(),
          if (_budgets.isNotEmpty) _summaryCard(spentSoFar, totalLimit),
          if (_budgets.isEmpty) _budgetsEmpty(),
          for (final b in _budgets) _budgetRow(b),
          _addButton(),
          const SizedBox(height: 10),
          _sectionTitle('Pasikartojantys'),
          _recurringCard(),
          const SizedBox(height: 12),
        ],
      ),
    );
  }

  Widget _header() => Padding(
        padding: const EdgeInsets.fromLTRB(16, 6, 16, 12),
        child: Row(children: [
          Text('Planavimas', style: TextStyle(fontSize: 30, fontWeight: FontWeight.w800, color: _ink, letterSpacing: -0.5)),
          const Spacer(),
          Icon(Icons.visibility_outlined, size: 25, color: _ink),
        ]),
      );

  Widget _monthFilter() {
    final isLatest = _selKey == null || _selKey == _monthKeys.last;
    final label = isLatest ? 'Šis mėnuo' : _monNom[_curMon - 1];
    return Padding(
      padding: const EdgeInsets.fromLTRB(16, 0, 16, 8),
      child: Row(children: [
        GestureDetector(
          onTap: _pickMonth,
          child: Container(
            padding: const EdgeInsets.symmetric(horizontal: 13, vertical: 9),
            decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(20), border: Border.all(color: _hair)),
            child: Row(mainAxisSize: MainAxisSize.min, children: [
              const Icon(Icons.calendar_today_rounded, size: 16, color: _purple),
              const SizedBox(width: 7),
              Text(label, style: TextStyle(fontSize: 14, fontWeight: FontWeight.w600, color: _ink)),
              const SizedBox(width: 4),
              const Icon(Icons.keyboard_arrow_down_rounded, size: 18, color: _purple),
            ]),
          ),
        ),
      ]),
    );
  }

  void _pickMonth() {
    final keys = _monthKeys.reversed.toList(); // newest first
    showModalBottomSheet<void>(
      context: context,
      isScrollControlled: true,
      backgroundColor: _card,
      shape: const RoundedRectangleBorder(borderRadius: BorderRadius.vertical(top: Radius.circular(22))),
      builder: (ctx) => SafeArea(
        child: Column(mainAxisSize: MainAxisSize.min, children: [
          const SizedBox(height: 12),
          Container(width: 40, height: 4, decoration: BoxDecoration(color: _faint, borderRadius: BorderRadius.circular(3))),
          Padding(padding: const EdgeInsets.fromLTRB(18, 14, 18, 6),
              child: Align(alignment: Alignment.centerLeft, child: Text('Pasirink mėnesį', style: TextStyle(fontSize: 19, fontWeight: FontWeight.w800, color: _ink)))),
          // Scrollable so a full year of months never overflows (was the yellow
          // overflow bar at the bottom of the sheet).
          Flexible(
            child: ListView(
              shrinkWrap: true,
              padding: const EdgeInsets.only(bottom: 10),
              children: [
                for (final k in keys)
                  InkWell(
                    onTap: () { setState(() => _selKey = k); Navigator.pop(ctx); },
                    child: Padding(
                      padding: const EdgeInsets.symmetric(horizontal: 18, vertical: 15),
                      child: Row(children: [
                        Text('${_monNom[int.parse(k.substring(5, 7)) - 1]} ${k.substring(0, 4)}',
                            style: TextStyle(fontSize: 16.5, fontWeight: k == _curKey ? FontWeight.w800 : FontWeight.w500, color: _ink)),
                        const Spacer(),
                        if (k == _monthKeys.last) Text('Šis mėnuo', style: TextStyle(fontSize: 12.5, color: _muted)),
                        if (k == _curKey) const Padding(padding: EdgeInsets.only(left: 8), child: Icon(Icons.check_rounded, size: 20, color: _purple)),
                      ]),
                    ),
                  ),
              ],
            ),
          ),
        ]),
      ),
    );
  }

  Widget _sectionTitle(String t) => Padding(
        padding: const EdgeInsets.fromLTRB(16, 8, 16, 10),
        child: Text(t, style: TextStyle(fontSize: 23, fontWeight: FontWeight.w800, color: _ink, letterSpacing: -0.3)),
      );

  Widget _banner() => Container(
        margin: const EdgeInsets.fromLTRB(16, 0, 16, 14),
        padding: const EdgeInsets.fromLTRB(16, 14, 12, 16),
        decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(16), border: Border.all(color: _hair)),
        child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          Row(crossAxisAlignment: CrossAxisAlignment.start, children: [
            Expanded(
              child: Text('Biudžetai padeda suvaldyti išlaidas',
                  style: TextStyle(fontSize: 17, fontWeight: FontWeight.w800, color: _ink, height: 1.25)),
            ),
            GestureDetector(
              onTap: () => setState(() => _showBanner = false),
              child: Icon(Icons.close_rounded, size: 20, color: _faint),
            ),
          ]),
          const SizedBox(height: 8),
          Text('Susikurk biudžetą kategorijai — limitą pasiūlysime pagal tavo realų mėnesių vidurkį.',
              style: TextStyle(fontSize: 14, color: _muted, height: 1.4)),
        ]),
      );

  // ── summary card: spent-so-far / total + projection area chart ───────────────
  Widget _summaryCard(double spent, double limit) {
    final pct = limit > 0 ? (spent / limit * 100).round() : 0;
    final budgetedSecs = _budgets.map((b) => b.sec).toSet();
    // cumulative daily spend across all budgeted sections, day 1..today
    final cum = <double>[];
    var run = 0.0;
    for (var day = 1; day <= _elapsedDays; day++) {
      final ds = '$_curKey-${day.toString().padLeft(2, '0')}';
      run += _rows
          .where((t) => t['d'] == ds && budgetedSecs.contains(t['sec']) && (t['a'] as num) < 0)
          .fold(0.0, (s, t) => s - (t['a'] as num).toDouble());
      cum.add(run);
    }
    final projected = _elapsedDays > 0 && cum.isNotEmpty ? cum.last / _elapsedDays * _daysInMonth : 0.0;
    final onTrack = projected <= limit;

    return Container(
      margin: const EdgeInsets.fromLTRB(16, 0, 16, 12),
      padding: const EdgeInsets.fromLTRB(16, 16, 16, 14),
      decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(16), boxShadow: DS.e1),
      child: Column(children: [
        Row(crossAxisAlignment: CrossAxisAlignment.center, children: [
          Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
            Text(_eur(spent), style: TextStyle(fontSize: 21, fontWeight: FontWeight.w800, color: _ink, letterSpacing: -0.4)),
            Text('išleista', style: TextStyle(fontSize: 13, color: _muted)),
          ]),
          const Spacer(),
          SizedBox(
            width: 62,
            height: 62,
            child: Stack(alignment: Alignment.center, children: [
              CustomPaint(size: const Size(62, 62), painter: _RingProgressPainter(pct / 100, onTrack ? _good : const Color(0xFFEE7A3A))),
              Text('$pct%', style: TextStyle(fontSize: 14, fontWeight: FontWeight.w800, color: _ink)),
            ]),
          ),
          const Spacer(),
          Column(crossAxisAlignment: CrossAxisAlignment.end, children: [
            Text(_eur(limit), style: TextStyle(fontSize: 21, fontWeight: FontWeight.w800, color: _ink, letterSpacing: -0.4)),
            Text('visas biudžetas', style: TextStyle(fontSize: 13, color: _muted)),
          ]),
        ]),
        const SizedBox(height: 16),
        SizedBox(
          height: 118,
          child: CustomPaint(
            size: Size.infinite,
            painter: _BudgetProjPainter(cum: cum, limit: limit, daysInMonth: _daysInMonth, elapsed: _elapsedDays, projected: projected, onTrack: onTrack),
          ),
        ),
        const SizedBox(height: 6),
        Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
          Text('1', style: TextStyle(fontSize: 12, color: _muted)),
          Text('8', style: TextStyle(fontSize: 12, color: _muted)),
          Text('16', style: TextStyle(fontSize: 12, color: _muted)),
          Text('24', style: TextStyle(fontSize: 12, color: _muted)),
        ]),
        const SizedBox(height: 8),
        Text(
          onTrack
              ? 'Tokiu tempu mėnesį baigsi ~${projected.round()} € — telpi į biudžetą.'
              : 'Tokiu tempu peršoksi biudžetą ~${(projected - limit).round()} € — sulėtink.',
          style: TextStyle(fontSize: 13.5, fontWeight: FontWeight.w600, color: onTrack ? _good : const Color(0xFFEE7A3A)),
        ),
      ]),
    );
  }

  // ── one budget row: name + limit, spent/left, paced progress bar ─────────────
  Widget _budgetRow(_Budget b) {
    final spent = _spentInSec(_rows, b.sec);
    final left = b.limit - spent;
    final frac = b.limit > 0 ? (spent / b.limit).clamp(0.0, 1.0) : 0.0;
    final col = _pace(spent, b.limit);
    return GestureDetector(
      onTap: () => _editBudget(b),
      child: Container(
        margin: const EdgeInsets.fromLTRB(16, 0, 16, 10),
        padding: const EdgeInsets.fromLTRB(14, 14, 14, 14),
        decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(16), border: Border.all(color: _hair)),
        child: Column(children: [
          Row(children: [
            CategoryIcon(icon: _iconOfSec(b.sec), color: _colorOfSec(b.sec), size: 40),
            const SizedBox(width: 12),
            Expanded(
              child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                Text(b.sec, style: TextStyle(fontSize: 16.5, fontWeight: FontWeight.w700, color: _ink)),
                 Text(b.isAuto ? 'Pasiūlyta pagal tavo išlaidas · keisk' : 'Tavo biudžetas · keisk',
                    style: TextStyle(fontSize: 11.5, color: _muted)),
              ]),
            ),
            Text(_eur(b.limit), style: TextStyle(fontSize: 16.5, fontWeight: FontWeight.w800, color: _ink)),
            const SizedBox(width: 3),
            Icon(Icons.edit_rounded, size: 15, color: _faint),
          ]),
          const SizedBox(height: 10),
          Row(children: [
            Text('${_eur(spent)} išleista', style: TextStyle(fontSize: 13.5, color: _muted)),
            const Spacer(),
            Text(
              left >= 0 ? '${_eur(left)} liko' : '${_eur(-left)} virš pasiūlymo',
              style: TextStyle(fontSize: 13.5, fontWeight: FontWeight.w700, color: col),
            ),
          ]),
          const SizedBox(height: 8),
          ClipRRect(
            borderRadius: BorderRadius.circular(6),
            child: Stack(children: [
              Container(height: 9, color: col.withValues(alpha: 0.14)),
              FractionallySizedBox(widthFactor: frac, child: Container(height: 9, color: col)),
            ]),
          ),
        ]),
      ),
    );
  }

  // Edit a budget's limit (turns an auto-suggested budget into a user-set one).
  void _editBudget(_Budget b) {
    final ctl = TextEditingController(text: b.limit.round().toString());
    showModalBottomSheet<void>(
      context: context,
      isScrollControlled: true,
      backgroundColor: _card,
      shape: const RoundedRectangleBorder(borderRadius: BorderRadius.vertical(top: Radius.circular(22))),
      builder: (ctx) => Padding(
        padding: EdgeInsets.only(bottom: MediaQuery.of(ctx).viewInsets.bottom + 20, left: 18, right: 18, top: 18),
        child: Column(mainAxisSize: MainAxisSize.min, crossAxisAlignment: CrossAxisAlignment.start, children: [
          Row(children: [
            CategoryIcon(icon: _iconOfSec(b.sec), color: _colorOfSec(b.sec), size: 34),
            const SizedBox(width: 10),
            Expanded(child: Text(b.sec, style: TextStyle(fontSize: 18, fontWeight: FontWeight.w800, color: _ink))),
            GestureDetector(onTap: () => Navigator.pop(ctx), child: Icon(Icons.close_rounded, color: _faint)),
          ]),
          const SizedBox(height: 6),
          Text(b.isAuto
              ? 'Šį limitą pasiūlėme pagal tavo ~3 mėn. vidurkį. Gali pakeisti į savo.'
              : 'Keisk savo mėnesio limitą.',
              style: TextStyle(fontSize: 13.5, color: _muted, height: 1.35)),
          const SizedBox(height: 16),
          Text('Mėnesio limitas', style: TextStyle(fontSize: 13, color: _muted, fontWeight: FontWeight.w600)),
          const SizedBox(height: 8),
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 14),
            decoration: BoxDecoration(color: _soft, borderRadius: BorderRadius.circular(12), border: Border.all(color: _hair)),
            child: Row(children: [
              Expanded(child: TextField(controller: ctl, keyboardType: TextInputType.number, autofocus: true,
                  style: TextStyle(fontSize: 22, fontWeight: FontWeight.w800, color: _ink),
                  decoration: const InputDecoration(border: InputBorder.none))),
              Text('€', style: TextStyle(fontSize: 22, fontWeight: FontWeight.w700, color: _muted)),
            ]),
          ),
          const SizedBox(height: 18),
          Row(children: [
            Expanded(
              child: GestureDetector(
                onTap: () { setState(() => _budgets.remove(b)); Navigator.pop(ctx); },
                child: Container(
                  padding: const EdgeInsets.symmetric(vertical: 15), alignment: Alignment.center,
                  decoration: BoxDecoration(borderRadius: BorderRadius.circular(14), border: Border.all(color: _hair)),
                  child: const Text('Pašalinti', style: TextStyle(fontSize: 15.5, fontWeight: FontWeight.w700, color: DS.danger)),
                ),
              ),
            ),
            const SizedBox(width: 10),
            Expanded(
              flex: 2,
              child: GestureDetector(
                onTap: () {
                  final v = double.tryParse(ctl.text.replaceAll(',', '.')) ?? 0;
                  if (v > 0) setState(() { b.limit = v; b.auto = false; });
                  Navigator.pop(ctx);
                },
                child: Container(
                  padding: const EdgeInsets.symmetric(vertical: 15), alignment: Alignment.center,
                  decoration: BoxDecoration(color: _purple, borderRadius: BorderRadius.circular(14)),
                  child: const Text('Išsaugoti', style: TextStyle(fontSize: 16, fontWeight: FontWeight.w800, color: Colors.white)),
                ),
              ),
            ),
          ]),
        ]),
      ),
    );
  }

  Widget _addButton() => Padding(
        padding: const EdgeInsets.fromLTRB(16, 2, 16, 2),
        child: GestureDetector(
          onTap: _openAddSheet,
          child: Container(
            padding: const EdgeInsets.symmetric(vertical: 16),
            alignment: Alignment.center,
            decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(16), border: Border.all(color: _hair)),
            child: const Row(mainAxisAlignment: MainAxisAlignment.center, children: [
              Icon(Icons.add_rounded, size: 22, color: _purple),
              SizedBox(width: 10),
              Text('Pridėti biudžetą', style: TextStyle(fontSize: 16, fontWeight: FontWeight.w700, color: _purple)),
            ]),
          ),
        ),
      );

  Widget _budgetsEmpty() => Padding(
        padding: const EdgeInsets.fromLTRB(16, 4, 16, 8),
        child: Container(
          padding: const EdgeInsets.all(18),
          decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(16), border: Border.all(color: _hair)),
          child: Column(children: [
            Icon(Icons.savings_outlined, size: 30, color: _muted),
            const SizedBox(height: 8),
            Text('Dar neturi biudžetų', style: TextStyle(fontSize: 15, fontWeight: FontWeight.w700, color: _ink)),
            const SizedBox(height: 4),
            Text('Pridėk kategoriją — pasiūlysim limitą pagal tavo tikras išlaidas, o tu patvirtinsi ar pakeisi.',
                textAlign: TextAlign.center, style: TextStyle(fontSize: 12.5, color: _muted, height: 1.35)),
          ]),
        ),
      );

  void _openAddSheet() {
    // Offer the full Vaultie spending taxonomy (minus income/transfers & the
    // already-budgeted ones) — a consistent set for every user, not just what
    // happened to be spent this month. Ordered by total historical spend so the
    // categories the user actually uses float to the top.
    final used = _budgets.map((b) => b.sec).toSet();
    const skip = {'Pajamos ir pervedimai', 'Kita'};
    final hist = <String, double>{};
    for (final t in widget.all) {
      if ((t['a'] as num) < 0) {
        hist[t['sec'] as String] = (hist[t['sec'] as String] ?? 0) - (t['a'] as num).toDouble();
      }
    }
    final options = [for (final e in _taxonomy) e['sec'] as String]
        .where((s) => !used.contains(s) && !skip.contains(s))
        .toList()
      ..sort((a, b) => (hist[b] ?? 0).compareTo(hist[a] ?? 0));
    if (options.isEmpty) return;
    showModalBottomSheet<void>(
      context: context,
      isScrollControlled: true,
      backgroundColor: _card,
      shape: const RoundedRectangleBorder(borderRadius: BorderRadius.vertical(top: Radius.circular(22))),
      builder: (_) => _AddBudgetSheet(
        options: options,
        colorOf: _colorOfSec,
        iconOf: _iconOfSec,
        suggestOf: _suggestLimit,
        onSave: (sec, limit) => setState(() => _budgets.add(_Budget(sec, limit))),
      ),
    );
  }

  // ── recurring block (reuses detected subscriptions) ──────────────────────────
  Widget _recurringCard() {
    final items = _recItems(widget.subs);
    final excl = DashboardStore.recurringExcluded();
    final incl = DashboardStore.recurringIncluded();
    final counted = items.where((it) => _recCounted(it, excl, incl)).toList()
      ..sort((a, b) => ((b['monthly'] ?? 0) as num).compareTo((a['monthly'] ?? 0) as num));
    final total = _recMonthlyTotal(items, excl, incl);
    return GestureDetector(
      onTap: () async {
        await Navigator.of(context).push(MaterialPageRoute(
            builder: (_) => _RecurringScreen(items: items)));
        if (mounted) setState(() {});
      },
      child: Container(
        margin: const EdgeInsets.fromLTRB(16, 0, 16, 4),
        padding: const EdgeInsets.fromLTRB(17, 16, 17, 16),
        decoration: BoxDecoration(
          borderRadius: BorderRadius.circular(20),
          gradient: const LinearGradient(begin: Alignment.topLeft, end: Alignment.bottomRight, colors: [Color(0xFF5A22C6), Color(0xFF7C3AED)]),
        ),
        child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          Row(children: [
            Expanded(
              child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                Text('${_eur(total)} / mėn', style: const TextStyle(fontSize: 22, fontWeight: FontWeight.w800, color: Colors.white, letterSpacing: -0.4)),
                const SizedBox(height: 2),
                Text('= ${_eur(total * 12)} per metus',
                    style: TextStyle(fontSize: 13.5, fontWeight: FontWeight.w700, color: Colors.white.withValues(alpha: 0.95))),
                const SizedBox(height: 3),
                Text('${counted.length} aktyvūs mokėjimai — bakstelėk tvarkyti',
