// ── Recurring manager (Monarch/Copilot-style) ───────────────────────────────
// Lists every detected recurring stream with its lifecycle status, and lets the
// user confirm the heuristic: keep a stream in the monthly commitment or drop it
// ("I stopped paying" / "not recurring"). Overrides persist in DashboardStore
// and re-apply after every re-sync (keyed by name), so a correction sticks.
class _RecurringScreen extends StatefulWidget {
  const _RecurringScreen({required this.items});
  final List<Map<String, dynamic>> items;
  @override
  State<_RecurringScreen> createState() => _RecurringScreenState();
}

class _RecurringScreenState extends State<_RecurringScreen> {
  late Set<String> _excl = DashboardStore.recurringExcluded();
  late Set<String> _incl = DashboardStore.recurringIncluded();
  // A STABLE order fixed on entry — counted first, then by amount. Toggling never
  // re-sorts (that made rows jump around and feel like the switch "sprang back").
  late final List<Map<String, dynamic>> _ordered = [...widget.items]..sort((a, b) {
        final ca = _recCounted(a, _excl, _incl), cb = _recCounted(b, _excl, _incl);
        if (ca != cb) return ca ? -1 : 1;
        return ((b['monthly'] ?? 0) as num).compareTo((a['monthly'] ?? 0) as num);
      });

  Future<void> _toggle(Map it, bool counted) async {
    final name = it['name'] as String;
    final backendActive = it['active'] == true && it['type'] != 'transfer';
    // Match the heuristic → clear the override; differ → store the user's choice.
    final bool? override = (counted == backendActive) ? null : counted;
    await DashboardStore.setRecurringOverride(name, override);
    if (!mounted) return;
    setState(() {
      _excl = DashboardStore.recurringExcluded();
      _incl = DashboardStore.recurringIncluded();
    });
  }

  // Name an anonymous recurring series (e.g. an "APPLE.COM/BILL" stream the bank
  // won't identify → "ChatGPT"). Stored against the series id (sid), so it only
  // renames THIS stream's charges — not one-off purchases at other amounts.
  Future<void> _rename(Map<String, dynamic> it) async {
    final sid = it['sid'] as String?;
    if (sid == null) return; // legacy/preview item without a series id
    final merchant = _shortNm((it['name'] as String?) ?? '—');
    final monthly = ((it['monthly'] ?? 0) as num).round();
    final ctl = TextEditingController(
        text: DashboardStore.subscriptionAliases()[sid] ?? '');
    final action = await showDialog<String>(
      context: context,
      builder: (ctx) => AlertDialog(
        backgroundColor: _card,
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(18)),
        title: Text('Pavadinti prenumeratą',
            style: TextStyle(color: _ink, fontWeight: FontWeight.w700, fontSize: 18)),
        content: Column(mainAxisSize: MainAxisSize.min, children: [
          Align(
            alignment: Alignment.centerLeft,
            child: Text('$merchant · $monthly € / mėn',
                style: TextStyle(color: _muted, fontSize: 13)),
          ),
          const SizedBox(height: 4),
          Align(
            alignment: Alignment.centerLeft,
            child: Text('Bankas nepasako, kas tai. Pavadink, kad atpažintum.',
                style: TextStyle(color: _faint, fontSize: 12)),
          ),
          const SizedBox(height: 12),
          TextField(
            controller: ctl,
            autofocus: true,
            textCapitalization: TextCapitalization.sentences,
            style: TextStyle(color: _ink, fontSize: 16, fontWeight: FontWeight.w600),
            decoration: InputDecoration(
              hintText: 'pvz. ChatGPT, iCloud, Spotify',
              hintStyle: TextStyle(color: _faint),
            ),
          ),
        ]),
        actions: [
          TextButton(
              onPressed: () => Navigator.pop(ctx, 'clear'),
              child: Text('Palikti kaip $merchant',
                  style: TextStyle(color: _muted, fontSize: 13))),
          TextButton(
              onPressed: () => Navigator.pop(ctx, 'save'),
              child: const Text('Išsaugoti',
                  style: TextStyle(color: _purple, fontWeight: FontWeight.w700))),
        ],
      ),
    );
    if (action == null) return;
    await DashboardStore.setSubscriptionAlias(
        sid, action == 'clear' ? null : ctl.text);
    _reloadSubAliases();
    if (mounted) setState(() {});
  }

  @override
  Widget build(BuildContext context) {
    final total = _recMonthlyTotal(_ordered, _excl, _incl);
    final countedN = _ordered.where((it) => _recCounted(it, _excl, _incl)).length;
    return Scaffold(
      backgroundColor: _bg,
      appBar: AppBar(
        backgroundColor: _bg,
        elevation: 0,
        foregroundColor: _ink,
        title: Text('Pasikartojantys', style: TextStyle(color: _ink, fontWeight: FontWeight.w800)),
      ),
      body: ListView(
        padding: const EdgeInsets.fromLTRB(16, 4, 16, 30),
        children: [
          Container(
            padding: const EdgeInsets.fromLTRB(18, 16, 18, 16),
            decoration: BoxDecoration(
              borderRadius: BorderRadius.circular(18),
              gradient: const LinearGradient(begin: Alignment.topLeft, end: Alignment.bottomRight, colors: [Color(0xFF5A22C6), Color(0xFF7C3AED)]),
            ),
            child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
              Text('${_eur(total)} / mėn', style: const TextStyle(fontSize: 24, fontWeight: FontWeight.w800, color: Colors.white)),
              const SizedBox(height: 2),
              Text('= ${_eur(total * 12)} per metus · $countedN įskaičiuota',
                  style: TextStyle(fontSize: 13, color: Colors.white.withValues(alpha: 0.9))),
            ]),
          ),
          Container(
            margin: const EdgeInsets.fromLTRB(2, 12, 2, 8),
            padding: const EdgeInsets.all(12),
            decoration: BoxDecoration(color: _purpleSoft, borderRadius: BorderRadius.circular(12)),
            child: const Row(children: [
              Icon(Icons.lightbulb_outline_rounded, size: 18, color: _purple),
              SizedBox(width: 10),
              Expanded(
                child: Text(
                    'Pasikartojančius mokėjimus atpažinti sunku — patikrink. Įjungti (žali) skaičiuojami į mėnesio sumą; nebemoki arba tai ne sąskaita — išjunk.',
                    style: TextStyle(fontSize: 12.5, color: _purpleDeep, height: 1.35)),
              ),
            ]),
          ),
          if (_ordered.isEmpty)
            Padding(padding: const EdgeInsets.all(16), child: Text('Pasikartojančių mokėjimų nerasta.', style: TextStyle(color: _muted))),
          for (final it in _ordered) _row(it),
        ],
      ),
    );
  }

  Widget _row(Map<String, dynamic> it) {
    final counted = _recCounted(it, _excl, _incl);
    final backendActive = it['active'] == true && it['type'] != 'transfer';
    final monthly = ((it['monthly'] ?? 0) as num).round();
    // The chip shows the EFFECTIVE state, so it can never contradict the switch:
    //  on  → "Įskaičiuota"; off → why it's out (detected status, or "Išjungta"
    //  when the user turned off a stream the app thought was active).
    final String chip;
    final bool live;
    if (counted) {
      chip = 'Įskaičiuota';
      live = true;
    } else {
      live = false;
      if (backendActive) {
        chip = 'Išjungta';
      } else {
        final m = _recStatusMeta(it['status'] as String?);
        chip = m[0].isNotEmpty ? m[0] : 'Neįskaičiuota';
      }
    }
    return Container(
      margin: const EdgeInsets.only(bottom: 8),
      padding: const EdgeInsets.fromLTRB(14, 10, 8, 10),
      decoration: BoxDecoration(color: _card, borderRadius: BorderRadius.circular(14), border: Border.all(color: _hair)),
      child: Row(children: [
        Expanded(
          child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
            Row(children: [
              Expanded(
                child: GestureDetector(
                  onTap: () => _rename(it),
                  behavior: HitTestBehavior.opaque,
                  child: Row(children: [
                    Flexible(child: Text(_recName(it), style: TextStyle(fontSize: 15.5, fontWeight: FontWeight.w700, color: counted ? _ink : _muted), overflow: TextOverflow.ellipsis)),
                    if (it['sid'] != null) ...[
                      const SizedBox(width: 5),
                      Icon(Icons.edit_outlined, size: 13, color: _faint),
                    ],
                  ]),
                ),
              ),
              const SizedBox(width: 8),
              Text('$monthly € / mėn', style: TextStyle(fontSize: 14, fontWeight: FontWeight.w800, color: counted ? _ink : _muted)),
            ]),
            const SizedBox(height: 4),
            Row(children: [
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 7, vertical: 2),
                decoration: BoxDecoration(color: (live ? _good : _muted).withValues(alpha: 0.14), borderRadius: BorderRadius.circular(6)),
                child: Text(chip, style: TextStyle(fontSize: 11, fontWeight: FontWeight.w700, color: live ? _good : _muted)),
              ),
              const SizedBox(width: 8),
              Expanded(child: Text(_recDetail(it), style: TextStyle(fontSize: 11.5, color: _faint), overflow: TextOverflow.ellipsis)),
            ]),
          ]),
        ),
        Switch.adaptive(value: counted, activeThumbColor: _purple, onChanged: (v) => _toggle(it, v)),
      ]),
    );
  }
}

